INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('_RJbVN6pdtaI', 'Genetik in 30 Sekunden', 'Jonathan Weitzman; Matthew Weitzman', 2024, 'Science', 'science', 'German', '9789089988812', 'Librero', 160, 4.7, 8, NULL, NULL, '… in 30 Sekunden', NULL, NULL, 'https://www.amazon.de/dp/1782405475', 'https://m.media-amazon.com/images/I/91rDCTYt1hL.jpg', 'Was ist die DNA und inwieweit bestimmen unsere Gene, wer wir sind? Wie wirkt eine Gentherapie? In den letzten hundert Jahren erlebte die Genetik atemberaubende Fortschritte. In diesem gut verständlichen Handbuch erfahren Sie alles Wesentliche zum Thema – von den Grundlagen bis aktuellen Forschungsergebnissen. Genetik in 30 Sekunden bricht den Fachjargon auf und berichtet von den Meilensteinen der Genetik, begonnen bei den Grundlagen der Zellbiologie bis zu den schier unglaublichen Entwicklungen in der DNA-Sequenzierung und der Genomchirurgie. Fortschritte bei der Stammzellentherapie, beim Klonen von Tieren, maßgeschneiderte Gentherapie und gentechnisch verändertes Getreide haben für Schlagzeilen gesorgt. Haben Sie sich je darüber Gedanken gemacht, was unter all dem zu verstehen ist und was das für unsere Zukunft bedeutet? Experten knacken in 50 Kapiteln den Code und entschlüsseln so die zentralen Begriffe und Ideen zur Genetik auf je einer Doppelseite in Wort und Bild. Dank der informativen Glossare, anschaulichen Grafiken und Biografien der wichtigsten Forscher werden Sie sich schon bald in diesem zentralen Wissenschaftsgebiet der Zukunft zu Hause fühlen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('tC_qd23AduIY', 'Swiss Made', 'R. James Breiding', 2012, 'Non-fiction', 'non-fiction', 'English', '9781898948202', 'Profile Books', 432, 3.94, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.com/dp/1898948201', 'https://covers.openlibrary.org/b/id/15195961-L.jpg', 'A comprehensive exploration of Switzerland''s economic success, "Swiss Made" by R. James Breiding delves into the factors contributing to the country''s global reputation for innovation, stability, and wealth. The book examines a range of industries, from finance and pharmaceuticals to technology and watchmaking, highlighting the cultural and historical influences that have shaped Switzerland''s unique business environment.', 'pax-audit-openlibrary', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('DJHRCgRo04-T', 'Der Crash kommt', 'Max Otte', 2019, 'Economics', 'finance', 'German', '9783426306253', 'Droemer Taschenbuch', 432, 3.8, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/3426306254', 'https://exlibris.azureedge.net/covers/9783/4263/0625/3/9783426306253xxl.webp', 'An analysis of economic trends and warnings about an impending financial crisis, "Der Crash kommt" by Max Otte anticipates the economic challenges and disruptions that could lead to a significant market crash.', 'pax-audit-openlibrary', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:46:40');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('cjiXHYQF4K1Q', 'Crashkurs – Dirk Müller', 'Dirk Müller', 2006, 'Economics', 'finance', 'German', '978-3938350149', 'Droemer Knaur', 349, 4.4, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/3938350140', 'https://images-na.ssl-images-amazon.com/images/P/3938350148.01.LZZZZZZZ.jpg', 'An engaging exploration of global financial markets, "Crashkurs" by Dirk Müller breaks down complex economic concepts for readers. Published in 2009, it offers insights into the causes and repercussions of the financial crisis, guiding readers through economic theories with practical advice and solutions. Known for his clear and approachable style, Müller provides a unique perspective from his experience in finance.', 'original', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:43:50');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('raSRTUkjjLrZ', 'Six Sigma für Dummies', 'Craig Gygi / Bruce Williams / Neil DeCarlo', 2006, 'Non-fiction', 'non-fiction', 'English', '978-0470045190', 'For Dummies', 318, 4.4, 107, NULL, '1.', '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/0470045191', 'https://m.media-amazon.com/images/I/71kWWG+fenL.jpg', 'Improve your efficiency -- and bring in big profits! Need help implementing or understanding Six Sigma? Want to take this powerful problem-solving methodology and apply it to your business? Six Sigma isn''t just for Fortune 500 companies anymore; it''s for every business, even yours, no matter how big or small. This hands-on workbook provides the knowledge, insight, and practical exercises you need to master Six Sigma and put it to work in your business. Perfect as a companion workbook for Six Sigma For Dummies -- or any other Six Sigma book -- Six Sigma Workbook For Dummies gives you a wealth of examples, problems, and other tools you need to turn Six Sigma theory into practice -- today! Discover * How to form and lead a Six Sigma initiative * Project alignment with business objectives and strategy * How to create process flow maps and models * Chart and graph plotting for analysis and interpretation * Methods for calculating Sigma scores * How to quantify variable relationships Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('E5uENuxFdwOr', 'Statistik mit Excel für Dummies', 'Joseph Schmuller', 2017, 'Non-Fiction', 'non-fiction', 'German', '978-3527713643', 'Wiley-VCH', 468, 4.8, 16, NULL, '7.', '… für Dummies', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/51X-Aoo-BHL.jpg', 'Java für Dummies ist gleichzeitig ein Lehrbuch und ein unverzichtbares Nachschlagewerk für alle Java-Programmierer. Basiswissen zur objektorientierten Programmierung wird genauso vermittelt wie das Prinzip der Wiederverwendbarkeit von Programmbausteinen und allgemeine Grundlagen der Java-Programmierung. Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('DOU7tony9Fgo', 'Übungsbuch Statistik für Dummies', 'Deborah J. Rumsey', 2016, 'Non-Fiction', 'non-fiction', 'German', '3527707071', 'Wiley-VCH', 368, 4.5, NULL, NULL, NULL, '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527707071', 'https://covers.openlibrary.org/b/id/14671956-L.jpg', 'A practical guide for students and professionals, providing clear explanations and exercises to master statistical concepts effectively.', 'pax-audit-openlibrary', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ocTmmscYYc87', 'Statistik für Dummies', 'Deborah J. Rumsey', 2014, 'Non-fiction', 'non-fiction', 'German', '978-3-527-71018-1', 'Wiley-VCH', 292, 4.4, 296, NULL, '1.', '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527710182', 'https://m.media-amazon.com/images/I/610vByMhHWL.jpg', 'Wollen Sie wissen, was mit Ihrem Geld gemacht wird? Dann sind Aktien für Sie die richtige Wahl, denn Sie haben es als Mitunternehmer in der Hand, wem Sie Ihr Geld anvertrauen. Doch was ist eigentlich das Grundprinzip von Aktien? Welche Vorteile haben sie gegenüber anderen Anlageformen? Wie kommen Sie an Aktien und wie ordern Sie geschickt, um Chancen zu nutzenund Risiken überschaubar zu halten? Was beeinflusst Kurse und wie analysieren Sie Kursverläufe, um den richtigen Zeitpunkt für Kauf und Verkauf abzupassen? Wie können Sie mit ganz einfachen Mitteln, Ihre eigene Anlagestrategie entwickeln? Diese und viele weitere Fragen rund um Aktien, Kursverläufe und Börsenpsychologie beantworten Ihnen die beiden Aktienexperten Dr. Christine Bortenlänger und Ulrich Kirstein in diesem Buch, das für die Shortlist des deutschen Finanzbuchpreises nominiert wurde. Damit auch Sie schon bald von Kursen und Dividenden profitieren! Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fh8gVaj1Wcxo', 'Logik für Dummies', 'Mark Zegarelli', 2016, 'Non-Fiction', 'non-fiction', 'German', '9783527711031', 'Wiley-VCH', 360, 4.2, 51, NULL, '1.', '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527711030', 'https://m.media-amazon.com/images/I/61-8hmewJmL.jpg', 'Logik ist die Basis der Wissenschaft, aber auch eine Brücke zwischen Wissenschaft und Alltag, denn die Grundlagen sind einfach logisch. Doch so einfach sie auf den ersten Blick scheint, so anspruchsvoll ist sie im Detail. "Logik kompakt für Dummies" führt Sie systematisch und so einfach wie möglich in dieses Teilgebiet von Mathematik und Philosophie ein. Dabei arbeitet Mark Zegarelli mit anschaulichen Beispielen und schafft es so, dieses abstrakte Thema nicht nur verständlich zu erklären, sondern auch Wert und Nutzen der Logik aufzuzeigen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('vT4kARjSbiAc', 'XML für Dummies', 'Lucinda Dykes / Ed Tittel', 2003, 'Non-fiction', 'non-fiction', 'German', '978-3-527-70129-0', 'Wiley-VCH', 304, 4.6, 12, NULL, '1.,', '… für Dummies', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/51VkA3-tD+L.jpg', 'Schlagzeug und Percussionsinstrumente gelten als leichter Einstieg in die Musik. Doch viele Anfänger stehen schon sehr bald vor dem Problem, die vielfältigen Möglichkeiten des Schlagzeugs zu meistern. Jeff Strong zeigt dem Leser, welche Instrumente zu einem Schlagzeug gehören und welche als Percussionsinstrumente eingesetzt werden. Vom einfachen Rhythmus bis zur lateinamerikanischen Musik, Jazz, Blues und Funk erfährt der Einsteiger alles Grundlegende zu Beats und Tempi. Mehr lesen', 'amazon_de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('klOfBdC281sw', 'Zeitmanagement für Dummies', 'Dirk Mayer', 2007, 'Self-help', 'self-help', 'German', '978-3527519303', 'Wiley-VCH', 352, 4.5, NULL, NULL, NULL, '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527519304', 'https://covers.openlibrary.org/b/id/2216020-L.jpg', NULL, 'pax-audit-openlibrary', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_6bc7a4389671', 'Wahrscheinlichkeitsrechnung für Dummies', 'Deborah Rumsey', 2007, 'Nonfiction', 'non-fiction', 'German', '978-3-527-70351-7', 'Wiley-VCH Verlag GmbH & Co. KGaA', 452, 3.9, 8, NULL, '1. Auflage', '… für Dummies', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/61hrecHTNDL.jpg', 'Beim Thema Rechtschreibung zucken viele zusammen. Schon in der Schule waren den meisten Diktate ein Graus. Groß- oder kleinschreiben, auseinander oder zusammen, und wo überhaupt muss ein Komma stehen oder ein Bindestrich? Peinlich, wenn dann später das Bewerbungsschreiben vor Fehlern nur so strotzt, die Examensarbeit inhaltlich zwar top, in Sachen Orthografie aber ein Flop ist oder in der Geschäftskorrespondenz mit wichtigen Kunden unzählige Kommafehler stecken. Ebenfalls unschön, wenn Newsletter und Flyer mehr durch ihre mangelhafte Rechtschreibung als durch ihren Inhalt auffallen. Hinzu kommt die Gewissheit, dass auf das Korrekturprogramm des PC auch kein Verlass ist. Und obendrein noch das Hin und Her um die Rechtschreibung in den letzten Jahren. Wer weiß da überhaupt noch, was Sache ist? Sich auf der Suche nach dem Neuen durch das amtliche Regelwerk zu wühlen, ist ein mühsames Geschäft. Das muss auch gar nicht sein. Dr. Matthias Wermke, der Leiter der Dudenredaktion, verbindet in "Neue deutsche Rechtschreibung für Dummies" die Kompetenz des Dudens mit dem lockeren Stil der Dummies, der Berührungsängste vor trockenen Themen nimmt. Und auf einmal werden die Regeln der neuen deutschen Rechtschreibung sogar Orthografiemuffeln verständlich. Als besonderes Extra enthält der Band ein Wörterbuch mit 47.000 Stichwörtern. Mehr lesen', 'amazon_de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_24509925f484', 'Mathe in 30 Sekunden', 'Richard J. Brown', 2012, 'Mathematics', 'science', 'German', '978-3-8310-2185-4', 'Dodax AG', 328, 3.59, NULL, NULL, NULL, '… in 30 Sekunden', NULL, NULL, 'https://www.dodax.de/de-de/buecher-hoerbuecher/mathematik/mathe-in-30-sekunden-richard-j-brown-dpI1Q50O9360/', 'https://images-na.ssl-images-amazon.com/images/P/3831021856.01.LZZZZZZZ.jpg', '"Mathe in 30 Sekunden" by Richard J. Brown is a concise exploration of key mathematical concepts, designed to explain complex ideas in brief, easily digestible segments. Each topic is intended to take 30 seconds to understand, making it an accessible resource for anyone interested in the fundamentals of mathematics. The book covers a wide range of topics from geometry to calculus, providing an engaging summary of essential mathematical principles.', 'original', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_2971171ded6f', 'Newton in 30 Sekunden', 'Brian Clegg', 2016, 'Science', 'science', 'German', '9789089987488', 'Librero', 160, 4.4, 12, NULL, NULL, '… in 30 Sekunden', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/614ooUnZWyL.jpg', 'Die Geschichte vom Apfel, der ihm auf den Kopf fiel, ist weltberühmt, aber was wissen Sie noch über Isaac Newton? Er war ein Multitalent – Physiker, Astronom, Alchemist und Mathematiker –, und die Genialität seines Werkes bahnte zahllosen wissenschaftlichen Entdeckungen den Weg. Frischen Sie Ihre Kenntnisse über sein beeindruckendes Erbe auf und lesen Sie Interessantes über ein Genie, das unsere Welt mitgeformt hat. Newton in 30 Sekunden vermittelt ein einzigartiges Bild eines der größten Genies aller Zeiten und präsentiert seine wichtigsten Ideen und Theorien. Jede Buchseite steckt voller Informationen: von seinen Entdeckungen zu Schwerkraft, Licht, Farben sowie Differential- und Integralrechnung bis zu seiner Zeit als Mitglied des Parlaments. Brian Clegg, Herausgeber, studierte Naturwissenschaften mit Schwerpunkt Experimentalphysik an der Universität Cambridge. Er schrieb für verschiedene Zeitschriften und Zeitungen wie Nature, The Times und The Wall Street Journal und unterrichtete an den Universitäten Oxford und Cambridge sowie der Royal Institution. Er ist Redakteur bei www.popularscience.co.uk und Verfasser zahlreicher Bücher, darunter Quantentheorie in 30 Sekunden. Mehr lesen', 'amazon_de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_b7c33e0b423d', 'Einstein in 30 Sekunden', 'Brian Clegg', 2017, 'Science', 'science', 'German', '9789089988799', 'Librero', 160, 4.1, 14, NULL, NULL, '… in 30 Sekunden', NULL, NULL, 'https://www.amazon.com/dp/1848312627', 'https://m.media-amazon.com/images/I/91y3kqxuwlL.jpg', 'Albert Einstein war ein bahnbrechendes Genie, dessen Ideen und Theorien die Wissenschaft revolutionierten. Mehr als einmal stellte er die Wahrnehmung des Universums auf den Kopf. Mit gerade einmal 26 Jahren sorgte der spätere Nobelpreisträger für wissenschaftlich spektakuläre Erkenntnisse. Albert Einstein war nicht nur ein herausragender Physiker, sondern außerdem ein Kämpfer für die Menschenrechte und ein politischer Aktivist. Einstein, der die wohl berühmteste Formel der modernen Physik E=mc2 formulierte, gilt bis heute als Prototyp des verschrobenen Professors. Einstein in 30 Sekunden eröffnet Ihnen die Gedankenwelt des wohl berühmtesten Physikers unserer Zeit, dessen außergewöhnliches Leben in gleichem Maße wie seine wissenschaftlichen Leistungen beeindruckt. Mit jedem der 50 informativen Kapitel werden sie Albert Einsteins Werk, Leben und Erbe besser verstehen – von der Relativitätstheorie über die Quantenphysik bis zur Kernspaltung. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_ce9e5dcf9490', 'Mythologie in 30 Sekunden', 'Robert A. Segal', 2024, 'Mythology', 'mythology', 'German', '9789089985958', 'Librero', 160, 4.7, 24, NULL, 'New', '… in 30 Sekunden', NULL, NULL, 'https://www.amazon.de/dp/9089985957', 'https://m.media-amazon.com/images/I/81fVIseZnZL.jpg', 'Mythologie in 30 Sekunden beleuchtet die wichtigsten Inhalte der bekanntesten klassischen Mythen und erklärt deren verborgene Bedeutung. Das Buch behandelt den Ursprung von Göttern, Helden und Dämonen der alten Griechen und Römer und erläutert dem Leser die grundlegenden Aspekte ihrer Überlieferungen in einer halben Minute auf jeweils zwei Seiten, in rund dreihundert Wörtern und anhand einer Abbildung. Mythologie in 30 Sekunden enthält die Biografien der sieben größten Dichter und Dramatiker des Altertums und verdeutlicht kurz und prägnant den bleibenden Einfluss antiker Mythen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_096439cc1d72', 'GRU – Die Speerspitze', 'Viktor Suworow', 2002, 'Non-fiction', 'non-fiction', 'German', '9783423205166', 'Goldmann', 329, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/3423205161', 'https://images-na.ssl-images-amazon.com/images/P/3423205164.01.LZZZZZZZ.jpg', 'Eigentlich hat sich Kommissar Laurenti auf eigenen ruhigen Triester Sommer eingestellt. Doch nach einem merkwürdigen Yacht-Unfall bekommt er es mit Mord, Geldwäsche und Menschenschmuggel zu tun. Darunter leidet nicht nur sein Familienleben ...', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:57:38');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_42ee89dbef0f', 'Kampf der Kulturen', 'Samuel P. Huntington', 2006, 'Political Science', 'political-science', 'German', '978-3492048461', 'Simon & Schuster; Rowohlt Taschenbuch Verlag', 536, 4.2, NULL, NULL, NULL, NULL, NULL, '["Berlin (Germany)"]', NULL, 'https://covers.openlibrary.org/b/id/1007600-L.jpg', 'An influential political science book that explores the theory of cultural conflicts shaping global politics post-Cold War, focusing on the idea that future wars would be fought not between countries, but between cultures.', 'pax-audit-openlibrary', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:01:47');
