INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_9f184abdafad', 'NSA – Amerikas geheimster Nachrichtendienst', 'James Bamford', 1983, 'Non-fiction', 'non-fiction', 'German', '9780140067484', 'Penguin Books', 655, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9780/1400/6748/4/9780140067484xxl.webp', 'An in-depth exploration of the National Security Agency (NSA), examining its secretive operations, history, and impact on global intelligence.', 'pax-audit-abebooks', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-13 23:04:28');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_82cfc37b6a9c', 'Reagan und die geheimen Kriege der CIA', 'Bob Woodward', 1987, 'Non-fiction', 'non-fiction', 'German', '9783426263402', 'Droemer Knaur', 447, 3.88, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/9783548357434', 'https://books.google.com/books?vid=ISBN9783426263402&printsec=frontcover&img=1&zoom=3', 'An investigative account by Bob Woodward detailing secret CIA operations during Ronald Reagan''s presidency, exploring the complexities and controversies of U.S. intelligence activities in the 1980s.', 'pax-audit-abebooks', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:06:15');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('bb0yOaScc7EE', 'Geheime Nachrichten-Technik', 'Otto Schreier', 1996, 'Military', 'history', 'English', '978-3-540-60605-6', 'Springer', 300, NULL, NULL, NULL, NULL, NULL, NULL, '["Science"]', NULL, 'https://images-na.ssl-images-amazon.com/images/P/354060605X.01.LZZZZZZZ.jpg', 'This volume is published in honor of Friedrich Hund''s 100th birthday. It is a modern review on matter at high densities and pressures in astrophysics from Hund''s early contribution to present-day ideas. The relation between the equation of state and the structure of compact cosmic objects is discussed, and two main contributions deal with the equation of state of baryonic matter at nuclear densities and with the numerical solution of the general relativistic field equations for non-rotating and rapidly rotating neutron stars. In a final chapter the present state of asteroseismology is presented as a tool to explore the interior of cosmic objects by analyzing the observed free oscillations of the Earth, the Sun, and white dwarf stars.', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:58:10');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fOcjD2CZC5jp', 'Nuclear Battlefields', 'William M. Arkin; Richard W. Fieldhouse', 1985, 'Non-fiction', 'non-fiction', 'English', '0871568530', 'Ballinger Publishing Company', 477, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.com/dp/0871568530', 'https://covers.openlibrary.org/b/id/6639865-L.jpg', 'A detailed examination of global nuclear weapons infrastructure during the Cold War, exploring the locations, strategies, and implications of nuclear arsenals and battlefields worldwide.', 'pax-audit-openlibrary', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('IB83F_KcAMLt', 'Credit Risk Modeling using Excel and VBA', 'Gunter Löffler; Peter N. Posch', 2010, 'Finance', 'finance', 'English', '9780470660928', 'Wiley', 368, 4.1, 51, NULL, '2.', NULL, NULL, '["Business & Economics"]', 'https://www.wiley.com/en-us/Credit+Risk+Modeling+using+Excel+and+VBA-p-9780470660928', 'https://m.media-amazon.com/images/I/718xMKcSdcL.jpg', 'It is common to blame the inadequacy of credit risk models for the fact that the financial crisis has caught many market participants by surprise. On closer inspection, though, it often appears that market participants failed to understand or to use the models correctly. The recent events therefore do not invalidate traditional credit risk modeling as described in the first edition of the book. A second edition is timely, however, because the first dealt relatively briefly with instruments featuring prominently in the crisis (CDSs and CDOs). In addition to expanding the coverage of these instruments, the book will focus on modeling aspects which were of particular relevance in the financial crisis (e.g. estimation error) and demonstrate the usefulness of credit risk modelling through case studies. This book provides practitioners and students with an intuitive, hands-on introduction to modern credit risk modelling. Every chapter starts with an explanation of the methodology and then the authors take the reader step by step through the implementation of the methods in Excel and VBA. They focus specifically on risk management issues and cover default probability estimation (scoring, structural models, and transition matrices), correlation and portfolio analysis, validation, as well as credit default swaps and structured finance. The book has an accompanying website, https://creditriskmodeling.wordpress.com/, which has been specially updated for this Second Edition and contains slides and exercises for lecturers. Mehr lesen', 'amazon_de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:44:02');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('xoKYLPLooJ1Y', 'Speed Reading', 'Tony Buzan', 1990, 'Non-fiction', 'non-fiction', 'English', '9780452266049', 'Penguin', 192, 4.2, 66, NULL, '3.', NULL, NULL, NULL, 'https://www.amazon.com/dp/0452266041', 'https://m.media-amazon.com/images/I/91SNW5KssmL.jpg', 'From the bestselling author of The Mind Map Book and Use Both Sides of Your Brain, dramatically increase your reading speed, comprehension, and retentionTony Buzan, world-famous expert in the field of the brain and the inventor of Mind Mapping, has gained international recognition with the methods outlined in Speed Reading. While it contains the traditional information on speed reading, this is the first book on the subject to utilize the latest discoveries about the astounding potential and intricate workings of your brain. In an easy-to-understand, direct style this classic guide provides: • New approaches to reading, study, concentration, and learning • Self-help tests designed to stimulate interest in different areas of knowledge • Measurement of your speed and comprehension to broaden your expertise. The revised Third Edition offers state-of-the-art techniques for improving reading speed and comprehension, from the simplest level to the most complex. Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:07:15');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('rNCGaoOV0CWb', 'MasterClass: Tony Buzan', 'Tony Buzan', NULL, 'Non-Fiction', 'non-fiction', 'English', NULL, 'Watkins Publishing; Watkins Publishing Ltd.', NULL, 3.9, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://images-na.ssl-images-amazon.com/images/I/41Hx-4kdZ8L._SX362_BO1,204,203,200_.jpg', 'A comprehensive guide by Tony Buzan on enhancing mental abilities and learning techniques, focusing on memory improvement, speed reading, and mind mapping strategies.', 'needs-manual-upload', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 10:05:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('YdjbaGjCMQGj', 'Exchange Traded Funds und Anlagestrategien: Das ETF-Praxisbuch', 'Norbert Niedermayer; Christian Wagner', 2012, 'Finance/Investment', 'finance', 'German', '9783033033023', 'financialmedia AG', 419, 4.7, 5, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783033033023&printsec=frontcover&img=1&zoom=3', 'Exchange Traded Funds (ETFs) sind in den vergangenen Jahren zu einem wichtigen Baustein vieler Anlagedepots geworden. Dank breiter Risikodiversifikation, tiefen Kosten und einfacher Handelbarkeit werden sie nicht mehr nur von Privatanlegern eingesetzt. Auch professionelle Vermögensverwalter und institutionelle Anleger greifen vermehrt auf ETFs zurück. Aber wie funktionieren ETFs genau und welche Chancen und Risiken bieten sie? Welche Märkte decken sie ab? Auf was ist bei der ETF- bzw. Index-Wahl beim Investieren in Aktien, Anleihen, Rohstoffe, Hedge Funds usw. zu achten? Diese Themen sowie konkrete Einsatzmöglichkeiten von ETFs in Anlagestrategien und verschiedene Tipps bei der Umsetzung von Investitionsentscheidungen stehen im Mittelpunkt dieses Buches. Für das Verständnis von praktischen Herausforderungen bedarf es theoretischer Grundlagen. Auch diese kommen nicht zu kurz: Von der Theorie der Risikodiversifikation, den Optimierungsmethoden von Portfolios bis zu den Tücken des Tracking Errors. Die ausgewählten Themen sollen dem Leser eine kritische Auseinandersetzung mit häufig gestellten Fragen aus der Investmentwelt ermöglichen und Hilfestellung leisten. Nicht zu kurz kommen die Vorstellung der grössten ETF-Anbieter, Unterschiede zwischen den bekannten US-Aktienindizes wie S&P 500, Dow Jones und Nasdaq sowie viele weitere Fragestellungen aus der Praxis. Das Buch ist von Praktikern für Praktiker geschrieben und soll allen, die mehr rund um das Thema ETFs und Anlagestrategien wissen wollen, den Überblick erleichtern. Das vorliegende Buch eignet sich insbesondere für: Interessierte Privatanleger, Kundenberater, Portfoliomanager, Studenten und Journalisten. 28.06.2012 / NZZ: "Mit «Exchange Traded Funds und Anlagestrategien» geben Daniel Niedermayer und Marcel Wagner einen Leitfaden, um ETF zu verstehen und richtig einzusetzen." 20.06.2012 / FuW: "Ein neues, umfassendes Werk über Exchange Traded Funds liegt vor." Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:55:58');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('kxnAxRC41Buk', 'Managing Credit Risk (Second Edition)', 'John Caouette; Edward I. Altman; Paul Narayanan; Nimmo', 2008, 'Finance', 'finance', 'English', '9780470118726', 'Wiley', 656, 4.2, 7, NULL, '2.', NULL, NULL, NULL, 'https://www.wiley.com/en-us/Managing+Credit+Risk%2C+Second+Edition-p-9780470118720', 'https://m.media-amazon.com/images/I/71WeZIoT6vL.jpg', 'Managing Credit Risk, Second Edition opens with a detailed discussion of today’s global credit markets―touching on everything from the emergence of hedge funds as major players to the growing influence of rating agencies. After gaining a firm understanding of these issues, you’ll be introduced to some of the most effective credit risk management tools, techniques, and vehicles currently available. If you need to keep up with the constant changes in the world of credit risk management, this book will show you how. Mehr lesen', 'amazon_de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:03:00');
