INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('tUzebbCnrDES', 'Astronomie', 'Karttunen, Kröger, Oja, Donner, Poutanen', 2018, 'Non-fiction', 'non-fiction', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/9175542-L.jpg', 'An exploration of astronomical concepts and phenomena, authored by experts in the field, offering insights into the universe''s mysteries and the scientific principles governing it.', 'pax-audit-openlibrary', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('JBDr_OCxNTZk', 'Die Kunst der Überlegenheit', 'Donald G. Krause', 1997, 'Business Strategy', 'business', 'Unbekannt', '9783832303440', 'Campus', 144, 4.0, NULL, NULL, '3.', NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783832303440&printsec=frontcover&img=1&zoom=3', 'Das Wesen des Führens zu verstehen und starke Führungsqualitäten herauszubilden, ist eine der wichtigsten Aufgabe heutiger Gesellschaften. Aber bereits in frühen Zeiten galt es als größte Herausforderung, Führungsqualitäten zu beweisen, vor allem dann, wenn die Bedingungen extrem schwierig waren. In diesem Zusammenhang kommt zwei Männern aus dem alten China ganz besondere Bedeutung zu: dem berühmten Feldherrn Sun Tzu und dem großen Philosophen Konfuzius. Kombiniert man ihre beiden Konzepte des Führens, so ergibt das ein System, das auch unter den schwierigsten Bedingungen funktioniert. Diesen Ansatz greift der Autor auf und überträgt die herausragenden militärischen und politischen Ideen direkt auf moderne Wirtschaftssituationen. Er bringt die philosophischen Visionen Sun Tzus und Konfuzius'' auf den Punkt und schafft so eine "Straßenkarte zum Erfolg". Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:52:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('N7WHvMmE5nwN', 'Spieltheorie für Führungskräfte', 'Volker Bieta; Wilfried Siebe', 1998, 'Business/Economics', 'finance', 'German', '9783832304096', 'Redline Wirtschaftsverlag', NULL, 5.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/8323/0409/6/9783832304096xxl.webp', 'Die Spieltheorie ist spätestens seit der Verleihung des Nobelpreises für Wirtschaftswissenschaften an den Deutschen Reinhard Selten auch hierzulande ein Begriff. Ohne mathematische Formeln und wissenschaftlichen Fachjargon erklärt dieses erste originär deutschsprachige Buch zur hochaktuellen Thematik anhand von vielen realen Beispielen, wie die Spieltheorie funktioniert, was sie leisten und was sie nicht leisten kann. Die Faktoren -Spieler-, -Strategie-, -Information-, -Wertschöpfung- und -Spielregeln- bestimmen das Spiel. Sie sind die Hebel, an denen angesetzt werden muss, um Spiele nach eigenen Zielen zu gestalten und zu verändern. Die Spiele sind Szenarien. Erst die gedankliche Disziplin, in der Spieltheorie gibt dann den (Management-)Szenarien die notwendige klare, auf wenige strategisch relevante Kernpunkte reduzierte Struktur. Durch den (Gedanken-)Rahmen der Spiele wissen die Spieler, was sie tun soll(t)en - und vor allem, wie sie es tun müssen, um ihre Ziele zu realisieren . Die Spieltheorie zeigt, wie man in konkreten Entscheidungssituationen die richtigen Entscheidungen finden kann, neue Sichtweisen von Situationen gewinnt und -Lösungen- in die Praxis umsetzt. Die anschaulichen Beispiele stammen zum großen Teil aus dem militärischen Bereich (Hannibal, Napoleon, Erster und Zweiter Weltkrieg, Golfkrieg), aber auch aus dem zivilen Leben (Krankenhaus-Management, Bank- und Börsengeschehen). Inzwischen haben auch amerikanische Business Consultants den Wert der Spieltheorie als Strategiepraktik für nichtmilitärische Zwecke erkannt. Für die erfolgreiche Umsetzung spieltheoretischer (Denk-)Logik in die Management-Praxis ist der Harvard-Management-Professor Michael Porter ein weltberühmter Zeitzeuge. Viele Regierungen und verschiedenste Organisationen in der ganzen Welt ziehen Spieltheoretiker als Berater heran. Noch dazu ist dieses bahnbrechende Buch auch eine Tour d-horizon durch die Geschichte des strategischen Denkens. Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:07:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Pjsb7xybsDTu', 'Elon Musk: Tesla, SpaceX, and the Quest for a Fantastic Future', 'Ashlee Vance', 2023, 'Biography', 'biography', 'Spanish', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8463846-L.jpg', 'A biography detailing the life and achievements of Elon Musk, focusing on his ventures with Tesla, SpaceX, and other groundbreaking projects, providing insights into his drive, innovation, and impact on the future of technology.', 'pax-audit-openlibrary', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:53:55');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('nmKezVUlnOi_', 'Gewinnen mit Börsenzyklen', 'Thomas Müller', 2007, 'Finance', 'finance', 'German', '9783930851652', 'TM Börsenverlag', 258, 3.3, 8, NULL, '4., Aufl.', NULL, NULL, '["Börsenkurs - Zyklus - Prognose 2005-2010"]', NULL, 'https://m.media-amazon.com/images/I/A1bh7Nm-wcL.jpg', 'Gewinnen mit Börsenzyklen Jeder Anleger kennt Jahresanfangs-Rallyes, Jahresend-Rallyes und die Sommerkorrekturen der Börsen. Diese Börsenphasen entstehen aber nicht zufällig, sondern wiederholen sich permanent, folgen also einem zyklischen Muster. Gewinnen mit Börsenzyklen zeigt anhand der kompletten Kurshistorie von Dax (seit 1959) und Dow Jones (seit 1896) den typischen zyklischen Kursverlauf der Börsen. Dabei wird eine detaillierte Untersuchung aller Jahres-Zyklen, Wahl-Zyklen, Zyklen der 4-Jahres-Tiefs, unterjährigen Zyklen und Jahrzehnt-Zyklen vorgenommen, so dass Gesamtverlauf und damit Start und Ende der entsprechenden Zyklen klar und nachvollziehbar werden. In insgesamt 31 Zyklen-Portfolios werden darauf basierende Anlagemodelle vorgestellt, die fast ohne Aufwand und mit einem deutlich reduzierten Risiko eine massive Outperformance von Dax und Dow Jones ermöglichen. Gegenüber einer Buy-and-Hold-Strategie lassen die Gewinne unter zu Hilfenahme von Zyklen sogar um das bis zu 33-fache steigern! Daneben zeigt eine ausführliche Besprechung der Demographie-Zyklen und der Technologie-Zyklen, warum die nächsten Jahre außergewöhnliche Börsenperspektiven eröffnen. Als Zusammenfassung aller behandelten Zyklen ergeben sich folgende Prognosen: - Dax und Dow Jones haben die Tiefs des Jahrzehnts schon hinter sich! - Die laufende Hausse wird sich bis 2009/2010 fortsetzen! - Das Mindestkursziel sind 10.000 für den Dax und 26.000/29.000 für den Dow Jones! - Vielleicht entsteht aber sogar eine noch viel größere Börsenblase als 1999/2000. Das würde bis Ende des Jahrzehnts zu noch deutlich höheren Notierungen führen, worauf ab 2010 aber eine Extrem-Baisse folgen sollte! Das Buch erklärt alle dominierenden Zyklen und skizziert daraus das wahrscheinlichste Bild für den Börsenverlauf der nächsten Jahre. Gewinnen mit Börsenzyklen ist das ultimative Basiswerk zu einem bisher fast unbekannten Analyseansatz, der in den nächsten Jahren noch erheblich an Popularität gewinnen wird. Mehr lesen', 'amazon_de', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:59:28');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Hb5oLXeEdba-', 'Die 24 Geheimnisse des George Soros', 'Robert Slater', 1998, 'Biography', 'biography', 'German', '9783832304126', 'Ueberreuter', 166, 5.0, NULL, NULL, '3.', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/71m9Vg9mERL.jpg', 'George Soros war bis zum Herbst 1992 nur wenigen außerhalb des Exklusivkreises der Hochfinanz ein Begriff. Das änderte sich schlagartig im September 1992: Er setzte darauf, daß Großbritannien aufgrund der immer flauer werdenden Wirtschaftslage zu einer Abwertung des britischen Pfundes gezwungen sein würde - und seine Spekulation ging auf. Als das Pfund am 15. September 1992 tatsächlich abgewertet wurde, verdiente Soros buchstäblich über Nacht eine Milliarde Dollar. - Ein Star war geboren. George Soros nimmt unbestritten den Rang des weltweit berühmtesten Investors ein. Kein anderer hat über einen so langen Zeitraum hinweg derart hervorragende Ergebnisse erzielt wie Soros. Einen besseren Lehrer als George Soros gibt es nicht. Seit 1969, dem Gründungsjahr seines Quantum-Fonds, hat Soros mit seinen Investitionen einen unglaublichen Rekord aufgestellt. Ein im Jahr 1969 in den Quantum-Fonds investierter Betrag von 1.000 Dollar wäre bei Wiederveranlagung der Dividenden bis zum Jah r 1995 auf 2,150.000 Dollar angewachsen. Dieses Buch gewährt einen Einblick in Soros'' Anlagestrategien. Viele dieser Denkansätze sind für den Kleinanleger ebenso anwendbar wie für den professionellen Investor. Zwar ist die Kenntnis der Geheimnisse hinter Soros'' Investitionserfolgen sicherlich keine Garantie dafür, daß der Leser über Nacht eine Milliarde Dollar verdienen wird. Doch kann er, indem er sich ein Bild von der Denk- und Arbeitsweise George Soros'' verschafft und seine Schlüsselstrategien gedanklich nachvollzieht, zu einem besseren Verständnis der komplexen Welt der Hochfinanz gelangen; er kann selbst ein gewisses Gespür dafür entwickeln, das Geschehen in den Finanzmärkten richtig zu interpretieren und daraus Gewinne zu erzielen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:51:51');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('AKs8bwhz5wpq', 'Sovereign Risk Analysis: A New Qualitative Hybrid Approach for Early Warning', 'Autor nicht eindeutig', NULL, 'Finance/Economics', 'finance', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'A comprehensive examination of sovereign risk assessment, introducing a novel qualitative hybrid approach for early warning, aimed at improving prediction and management in financial and economic sectors.', 'needs-manual-upload', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 10:05:27');
