INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('TyfsRx6-bL_9', 'Die Kunst des Krieges für Führungskräfte', 'Donald G. Krause', 1996, 'Business Strategy', 'business', 'German', '9783832301866', NULL, 150, 3.5, 11, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783832301866&printsec=frontcover&img=1&zoom=3', 'A strategic business book that adapts the ancient wisdom of Sun Tzu''s "The Art of War" into practical advice for leaders and executives, providing insights into effective decision-making, management, and competitive strategies in the corporate world.', 'original', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:52:48');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('HQqA2_9lzZih', 'Es war einmal ein Zebra, das liebte die Algebra', 'Markus Marty', 2019, 'Children''s Literature', 'children''s-literature', 'German', '9783990184806', 'Bucher Verlag GmbH', 56, 5.0, NULL, NULL, '1.', NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/9901/8480/6/9783990184806xxl.webp', 'Die köstlichen, spannenden Ministorys, zu heiter berührenden Versen verdichtet, sprühen vor Lebensfreude. Marty nutzt dabei die Tiefe und Bedeutungsvariationen der Worte und bietet dem Leser so die Möglichkeit, in eine weitere Ebene einzutauchen. Wie ansonsten bei seiner Arbeit mit Düften, geht der Parfumeur hier auf die »Seele« der Worte ein. Ein Geschenk im besten Sinne des Wortes. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:54:24');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ZSU3ip4wncWj', 'Rhetorik – Handbuch der Redekunst (Band 2)', 'Roman Hofmeister', 1993, 'Non-Fiction', 'non-fiction', 'German', '9783850122641', 'Weltbild, Augsburg,', 600, 5.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://pictures.abebooks.com/isbn/9783850122641-de-300.jpg', 'A comprehensive guide to the art of rhetoric, this volume by Roman Hofmeister delves into advanced techniques and strategies for effective public speaking, offering insights into persuasion, audience engagement, and speech crafting. Published in 2020, it serves as an essential resource for those looking to refine their communication skills in various contexts.', 'pax-audit-abebooks', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 10:09:21');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('1B-T-NtWTJbF', 'Rhetorik – Handbuch der Redekunst (Band 1)', 'Roman Hofmeister', 1993, 'Non-fiction', 'non-fiction', 'German', '9783850122641', 'Weltbild, Augsburg,', 600, 5.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/61ft-dIgvXL.jpg', 'Comprehensive guide to the art of rhetoric, offering insights into effective public speaking and persuasive communication techniques.', 'pax-audit-openlibrary', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:06:44');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('rk9xerhM7ofC', 'Die 222 wichtigsten Fragen zu Derivaten', 'Volker Meinel', 2007, 'Finance', 'finance', 'German', '9783898792110', 'FinanzBuch Verlag', 256, 3.0, NULL, NULL, '1.', NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783898792110&printsec=frontcover&img=1&zoom=3', 'Ob Optionen, Futures oder Swaps – die Welt der Derivate ist vielfältig und für Privatanleger nicht immer leicht zu durchschauen. Oft können einem auch Banken und Anlageberater nicht weiterhelfen. Volker Meinel, selbst Banker mit einem offenen Ohr für seine Kunden, kämpft gegen diesen Missstand an. Nun hat Meinel seine jahrelangen Erfahrungen in 222 Fragen und Antworten zusammengefasst. Der Leser erhält einen optimalen Überblick über die Märkte und ist in der Lage, selbst erfolgreich an den weltweiten Finanzmärkten zu bestehen. - Der Autor bringt seine Erfahrung aus unzähligen Leserbriefen, Telefonaten und Messegesprächen ein - Ein weiteres Highlight aus der Reihe »Die 222 wichtigsten Fragen zu …« - Umfassende Einblicke in die Welt der Derivate - Durch das Frage-Antwort-Schema übersichtlich gegliedert Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:51:24');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6r6T20vq5oOS', 'Forex Conquered', 'John L. Person', 2007, 'Finance', 'finance', 'English', '9780470127049', 'John Wiley & Sons', 306, NULL, NULL, NULL, NULL, NULL, NULL, '["Business & Economics"]', NULL, 'https://exlibris.azureedge.net/covers/9780/4701/2704/9/9780470127049xxl.webp', 'Praise for FOREX CONQUERED "In this amazing book, John covers it all. From trading systemsto money management to emotions, he explains easily how to pullmoney consistently from the most complicated financial market inthe world. John packs more new, innovative information into thisbook than I have ever seen in a trading book before." —Rob Booker, independent currency trader "John Person is one of the few rare talents that are uniquelyqualified to help traders understand the process of successfultrading. With today''s markets becoming increasingly challenging,John has cut right into the essentials and brought forward themuch-needed tools of forex trading. This clear and well-organizedpublication is a major step forward in helping traders gain anedge. I would highly recommend Forex Conquered as a valuablehandbook for both aspiring and experienced traders alike." —Sandy Jadeja, Chief Market Analyst and EditorLondon StockExchange, London, England "Forex Conquered is a bold title, but this book deliversthe tools needed for successful forex trading. There is no fluffhere, just the wisdom of a trading veteran that I have alwaysrespected-and followed." —Michael Kahn, Editor, Quick Takes Pro market letterand Columnist, Barron''s Online "This is a wonderful, in-depth view into the explanation oftechnical analysis and prudent money management guidelines in theforex market." —Blake Morrow, President, 4XMadeEasy "Forex Conquered is a meaningful contribution to the growingnumber of books on forex trading. John Person provides aprofessional view of forex trading that readers will be able to useas a guide for strategies and tactics that work. The scope of thebook covers more than forex and includes salient aspects of futuresand option trading. It should be read and then re-read!" —Abe Cofnas, President, Learn4x.com Note: CD-ROM/DVD and other supplementary materials arenot included as part of eBook file.', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:57:00');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('8uo8rUuYgdhc', 'Der Schwarze Schwan', 'Nassim Nicholas Taleb', 2021, 'Non-fiction', 'non-fiction', 'German', '9783641281779', 'Penguin Verlag', 810, NULL, NULL, NULL, NULL, NULL, NULL, '["Social Science"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6412/8177/9/9783641281779xxl.webp', 'Die Weltbestseller des großen Zufallsforschers Ein “Schwarzer Schwan” ist ein Ereignis, auf das drei Dinge zutreffen: Es ist erstens ein Ausreißer – es liegt außerhalb der regulären Erwartungen, nichts in der Vergangenheit weist darauf hin. Es hat zweitens enorme Auswirkungen. Drittens bringt uns die menschliche Natur dazu, im Nachhinein Erklärungen für sein Eintreten zu konstruieren, um es erklärbar und vorhersagbar zu machen. In diesem bahnbrechenden Buch, das mittlerweile weltweit zum Klassiker geworden ist, entwickelt Taleb seine einflussreiche Denkfigur und Maxime für die ungewisse Realität, in der wir leben und handeln. Talebs Weltbestseller – „Der Schwarze Schwan: Die Macht höchst unwahrscheinlicher Ereignisse“ und „Der Schwarze Schwan: Konsequenzen aus der Krise“ – in einem Band und eingeleitet mit einem neuen Essay des Autors »Eines der zwölf einflussreichsten Bücher seit dem Zweiten Weltkrieg.« (Sunday Times) »›Der Schwarze Schwan‹ hat meine Sicht auf die Welt verändert.« (Daniel Kahneman, Nobelpreisträger) Der Weltbestseller: übersetzt in 33 Sprachen mit über 3 Millionen verkauften Exemplaren »Taleb zerpflückt mit großer Lust und einem guten Schuss Polemik unseren offenbar unerschütterlichen Glauben an die Vorhersehbarkeit von Ereignissen.« (SWR)', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:48:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('0XjBem6mtHxK', 'Zeitmanagement mit Outlook', 'Schwert; Wagner; Obermayr', 2010, 'Non-fiction', 'non-fiction', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/9531099-L.jpg', 'A comprehensive guide on utilizing Microsoft Outlook for effective time management, written by Schwert, Wagner, and Obermayr. This non-fiction book provides strategies and tips for optimizing productivity and organizing tasks using Outlook''s features.', 'pax-audit-openlibrary', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('MfS9FyVvUd9f', 'Fighter Wing', 'Tom Clancy', 2007, 'Military Fiction', 'thriller', 'English', '9781101002575', 'Penguin', 386, NULL, NULL, NULL, NULL, NULL, NULL, '["History"]', NULL, 'https://exlibris.azureedge.net/covers/9781/1010/0257/5/9781101002575xxl.webp', 'Now, for the first time, an insider''s look at an Air Force combat wing -- the planes, the technology, and the people . . . with Tom Clancy as your guide. Tom Clancy''s previous explorations of America''s armed forces, Submarine and Armored Cav, revealed exclusive, never-before-seen information an the people and technology that protect our nation. Now, the acclaimed author of Clear and Present Danger and Debt of Honor takes to the skies with the U. S. Air Force''s elite: the Fighter Wing. With his compelling style and unerring eye for detail, Clancy captures the thrill of takeoff, the drama of the dogfight, and the relentless dangers our fighter pilots face every day of their lives . . . showing readers what it really means to be the best of the best. Fighter Wing includes: Detailed analyses of the Air Force''s premier fighter planes, including the F-15 Eagle Exclusive photographs, illustrations, and diagrams An insider''s look at the people behind the planes and weapons Combat strategies and training techniques used by the U. S. Air Force', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:56:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('auoumYaNtDDw', 'Das Echo aller Furcht', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641089924', 'Heyne Verlag', 951, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8992/4/9783641089924xxl.webp', 'Der Kalte Krieg scheint Vergangenheit, die Weltmächte verhandeln im Zeichen der Kooperation und setzen auf eine friedliche Zukunft. Doch hinter den Kulissen tickt eine gefährliche Zeitbombe, und ein seltsamer Bombenfund genügt, um einen weltumspannenden tödlichen Konflikt zu entfachen. Jack Ryan, Amerikas Geheimdienstmann für Top-Secret-Fälle, muss einen nahezu aussichtslosen Kampf gegen die Zeit gewinnen ...', 'google_books', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:44:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fujtRVEV0NDu', 'Rainbow Six', 'Tom Clancy', 1998, 'Techno-thriller', 'thriller', 'Chinese', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/3100545-L.jpg', 'An action-packed techno-thriller novel featuring an elite multinational counter-terrorism unit called Rainbow, led by John Clark, as they tackle various global threats with cutting-edge technology and intense tactical operations.', 'original', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('v22xVeqgfmdQ', 'Im Auge des Tigers', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641085803', 'Heyne Verlag', 398, 4.5, 2, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8580/3/9783641085803xxl.webp', 'Die neue Form des internationalen Terrorismus fordert eine neue Generation von Jägern heraus: Es kommt die Zeit für Jack Ryan, Jr. und seinesgleichen. Ein Mann namens Mohammed sitzt in einem Wiener Kaffeehaus und schlägt einem Kolumbianer ein Geschäft vor: Mohammed hat ein starkes Netzwerk aus Agenten und Sympathisanten in ganz Europa und im Mittleren Osten, und der Kolumbianer ein ähnlich starkes Netzwerk im Drogenhandel Amerikas. Warum sollten sie nicht eine Allianz bilden? Das Potential für Profit wäre riesengroß – und das Potential für Zerstörung unvorstellbar.', 'google_books', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:00:30');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('LpzIOoT90DCE', 'Der Kardinal im Kreml', 'Tom Clancy', 2012, 'Techno-thriller', 'thriller', 'German', '9783641088576', 'Heyne Verlag', 422, 5.0, 1, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8857/6/9783641088576xxl.webp', 'Von einem geheimen Ort in der Nähe der afghanischen Grenze aus haben Russen erstmals mit einem Laserstrahl einen US-Spionagesatelliten "geblendet". Ein Fall für Jack Ryan. «Ein Autor, der nicht in Science-fiction abdriftet, sondern realistische Ausgangssituationen spannend zum Roman verdichtet.» DER SPIEGEL', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:47:42');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('T9Z8XM8Gd0qC', 'Im Sturm', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641089917', 'Heyne Verlag', 768, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8991/7/9783641089917xxl.webp', 'Das Attentat arabischer Fundamentalisten auf eines der wichtigsten Ölfelder Sibiriens bringt die GUS in einen fatalen Zugzwang. Um den Zusammenbruch ihrer maroden Wirtschaft zu verhindern, erzwingt Moskau sich Zugang zum Persischen Golf und schreckt auch vor einem Schlag gegen die NATO nicht zurück ...', 'google_books', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:01:02');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('5MjlkjYcDpo6', 'Der Schattenkrieg', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641089900', 'Heyne Verlag', 615, 5.0, 2, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8990/0/9783641089900xxl.webp', 'Als kolumbianische Drogenbosse drei hochrangige US-Amerikaner töten, ist für den Geheimdienstmann Jack Ryan der Punkt erreicht, an dem er zurückschlagen muss. Er stellt eine Truppe kampferprobter Männer zusammen und führt sie in einen Schattenkrieg, in dem die üblichen Regeln nicht gelten.', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:48:13');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Vgbq-K_Y1G-N', 'Gnadenlos', 'Tom Clancy', 2017, 'Thriller', 'thriller', 'German', '9783641226640', 'Heyne Verlag', 699, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6412/2664/0/9783641226640xxl.webp', 'John Kelly, ehemaliger US-Marine und Spezialist für riskante Missionen, erhält den Auftrag, amerikanische Geiseln aus Nordvietnam herauszuholen - eine beinahe aussichtslose Mission, zumal Kelly sich gerade durch einen privaten Rachefeldzug in Lebensgefahr gebracht hat. Ein Wettlauf gegen die Zeit beginnt, und der geringste Fehler könnte sein letzter sein ...', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 23:00:00');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Wst-0OfzmhAb', 'Befehl von oben', 'Tom Clancy', 2013, 'Thriller', 'thriller', 'German', '9783641089061', 'Heyne Verlag', 1098, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8906/1/9783641089061xxl.webp', 'Jack Ryans schwerste Stunde Bei einem Flugzeugangriff auf das Kapitol kommt der amerikanische Präsident ums Leben. Spezialagent Jack Ryan, vor Kurzem zum Vizepräsidenten ernannt, muss von einem Tag auf den anderen die Amtsgeschäfte übernehmen. Derweil nutzen Amerikas Feinde ihre Chance: China und Taiwan stehen kurz vor einem Krieg, und der Iran plant, amerikanische Großstädte mit einem tödlichen Virus zu verseuchen ...', 'google_books', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-13 22:42:07');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('2__5JtUXjJ_D', 'Ehrenschuld', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783453436787', 'Heyne Verlag', 1040, 4.4, 941, NULL, NULL, 'Jack Ryan', 8, NULL, NULL, 'https://m.media-amazon.com/images/I/91DSsW0hdEL.jpg', 'Jack Ryans härtester Einsatz Außenpolitisch stehen die USA kurz vor der Alarmstufe Rot. Man holt Jack Ryan als neuen Sicherheitsberater des Präsidenten an die vorderste Front. Doch bevor er loslegt, muss Ryan zuerst noch eine Ehrenschuld begleichen. Ein Politthriller der Sonderklasse! Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:53:20');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('EbX3iNmGXb2U', 'Im Zeichen des Drachen', 'Marc Olden', 2001, 'Thriller', 'thriller', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/2206056-L.jpg', 'A gripping thriller set against the backdrop of international espionage and intrigue, "Im Zeichen des Drachen" weaves a complex tale of power struggles and clandestine operations. As tensions rise, protagonists must navigate a world filled with danger and deception, where allegiances are tested and nothing is what it seems.', 'pax-audit-openlibrary', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 12:31:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('-X1sZeJKiOPm', 'Gegen alle Feinde', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641085827', 'Heyne Verlag', 741, 4.0, 13, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8582/7/9783641085827xxl.webp', 'Internationale Intrigen, explosive Action – der neue große Tom Clancy Seit Jahren tobt der Konflikt im Mittleren Osten. Nun sieht es so aus, dass sich der Kriegsschauplatz verlagert hat. Die Taliban bedienen sich für ihre Machenschaften eines mexikanischen Drogenkartells und tragen den Kampf ins Heimatland des Erzfeindes – in die Vereinigten Staaten von Amerika. Tom Clancy, der Meister des internationalen Politthrillers, stellt uns seinen neuen Helden vor: Ex-Navy-SEAL Max Moore. Und der steht allein – gegen alle Feinde.', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:58:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6nC6RXBto_LU', 'Ziel erfasst', 'Tom Clancy', 2014, 'Thriller', 'thriller', NULL, '9783453267398', 'Heyne', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783453267398&printsec=frontcover&img=1&zoom=3', 'A high-stakes thriller set in the world of espionage and military tactics, where intricate plots and international intrigue challenge characters to navigate a dangerous game of cat and mouse.', 'pax-audit-verlag-penguin', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-13 23:11:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('M366WVN8yNge', 'The European Dream', 'Jeremy Rifkin', 2004, 'Non-fiction', 'non-fiction', 'Spanish', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/483335-L.jpg', 'The European Dream by Jeremy Rifkin explores the evolving European identity and contrasts it with the American Dream. It delves into how Europe’s vision emphasizes community, sustainability, and quality of life over individual success and material wealth. Rifkin argues that the European model offers a more sustainable and equitable future for a globalized world.', 'original', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-12 19:22:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('R4trCgIlkTfv', 'The Age of Access', 'Jeremy Rifkin', 2000, 'Non-fiction', 'non-fiction', 'English', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/6798299-L.jpg', 'A compelling exploration of how the shift from ownership to access is transforming the economy, culture, and daily life, where traditional markets are being replaced by networks and services.', 'original', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-12 19:21:43');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('9KZtm5uDMO4Q', 'The Hydrogen Economy', 'Jeremy Rifkin', 2002, 'Non-fiction', 'non-fiction', 'Russian', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/850150-L.jpg', 'Explores the potential of hydrogen as a sustainable energy source and its role in addressing global energy and environmental challenges.', 'original', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-12 19:22:56');
