INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ai0JDC9kz4le', 'Das Quark und der Jaguar', 'Murray Gell-Mann', 1996, 'Non-fiction', 'non-fiction', 'German', '9783492222969', 'Piper', 528, 5.0, 4, NULL, '3.,', NULL, NULL, '["Komplexität"]', NULL, 'https://m.media-amazon.com/images/I/81l-GN1vaNL.jpg', 'A profound exploration of the complexities of nature, where the author, a Nobel Prize-winning physicist, delves into the interconnectedness of simple and complex phenomena, examining topics from particle physics to the processes of human consciousness and the universe''s intricate tapestry.', 'original', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:45:05');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('dl-tJXLrboMK', 'Einsteins Universum', 'Nigel Calder', 2005, 'Science', 'science', 'sv', '9789185251353', NULL, 235, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9789185251353&printsec=frontcover&img=1&zoom=3', 'A comprehensive exploration of Einstein''s theories, delving into the concepts of relativity and their impact on our understanding of the universe, presented in an accessible manner for a broad audience.', 'original', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:53:55');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('UWsoKaP8FZ_c', 'Kitsch ist Geschmackssache', 'Anja Weber', 2016, 'Non-fiction', 'non-fiction', 'German', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Explores the subjective nature of taste and kitsch, examining cultural, social, and personal factors that influence perceptions of aesthetic value.', 'needs-manual-upload', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 10:05:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('eBeYLxrTwmfJ', 'Der Traum von der Einheit des Universums', 'Steven Weinberg', 1995, 'Non-fiction', 'non-fiction', 'German', '9783442126415', 'GOLDMANN, WILHELM', 320, 3.5, 2, NULL, '1.', NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783442126415&printsec=frontcover&img=1&zoom=3', 'A comprehensive exploration of the quest for a unified theory of fundamental forces, reflecting on the history, challenges, and scientific milestones in physics.', 'pax-audit-exlibris-ch', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:49:09');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('X3FOviQbQ2qy', 'Der grosse Entwurf', 'Stephen Hawking; Leonard Mlodinow', 2010, 'Science', 'science', 'German', '9783498029913', 'Rowohlt Buchverlag', 192, 4.5, 124, NULL, '3.', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/71cskkXXWoL.jpg', 'Warum existieren wir? – Neue Antworten auf die letzten fragen des Seins «Um das Universum auf fundamentalster Ebene zu verstehen, müssen wir nicht nur wissen, wie sich das Universum verhält, sondern auch, warum. Warum gibt es etwas und nicht einfach nichts? Warum existieren wir? Warum dieses besondere System von Gesetzen und nicht irgendein anderes? Das ist die letztgültige Frage nach dem Leben, dem Universum und dem ganzen Rest. Wir werden versuchen, sie in diesem Buch zu beantworten.» Stephen Hawking Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:50:16');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('pmrwOETwDPnn', 'Das Universum in der Nussschale', 'Stephen Hawking', 2004, 'Non-fiction, Science', 'science', 'German', '9783423340892', 'dtv Verlagsgesellschaft mbH & Co. KG', 264, 4.8, 469, NULL, '2.', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/71CzyveBgLL.jpg', 'Über das surreale Wunder der modernen Raumzeit-Forschung Wie kam es, dass in einer bestimmten Phase der kosmischen Entwicklung Milliarden Sterne »angingen«, wie tickt das Uhrwerk, das sie dazu veranlaßte? Warum glüht der Himmel nicht, obwohl doch das ganze Universum glüht - oder stimmt das gar nicht? Warum bewegt sich das Universum von uns fort? Warum haben Raum und Zeit einen Anfang und sind nicht ewig? Warum ist die Welt nicht fest umrissen und endgültig? Warum sind wir eigentlich hier und nicht woanders? Gibt es im All andere Wesen, und wenn ja, wer sind sie, und wo sind sie? Die Suche nach der Formel, die das Universum erklärt, nach der »Theorie für alles« ist der heilige Gral der Physik. Stephen Hawking behandelt in ›Das Universum in der Nussschale‹ verschiedene Vorschläge dafür, wie zum Beispiel die String-Theorie und Super-Gravitation. Er zeigt, dass nicht jeder Raum, sondern auch jede Zeit eine Form annimmt. Er pokert mit Newton und Einstein, befasst sich mit der Frage, ob Zeitreisen möglich sind, sowie mit anderen kühnen Spekulationen und bietet einen einzigartigen Einblick in die Welt der modernen Astrophysik und Kosmologie. Taschenbuchausgabe auf der Grundlage der erweiterten Neuausgabe. Mit zahlreichen Abbildungen. Mehr lesen', 'amazon_de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:45:38');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('HnzOuE694oGA', 'Wirtschaftsfreiheit und begrenzte Staatsverantwortung', 'Klaus A. Vallender; Jens Lehne; Peter Hettich', 2006, 'Non-fiction', 'non-fiction', 'German', '9783727207846', 'Stämpfli Verlag AG', 1098, 5.0, NULL, NULL, '4.,', NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783727207846&printsec=frontcover&img=1&zoom=3', 'Das Werk macht die Leserinnen und Leser mit den zentralen Elementen der schweizerischen Wirtschaftsverfassung vertraut und zeigt auf, wie der Gesetzgeber das Wirtschaftsverwaltungsrecht auf der Grundlage der Vorentscheide, Zielvorgaben und Aufträge des Verfassungsgebers ausgestaltet hat. Seit der dritten Auflage ist einerseits die neue Bundesverfassung in Kraft getreten, andererseits haben zahlreiche Bereiche des Wirtschaftsverwaltungsrechts umfassende Änderungen erfahren, die in der Neuauflage berücksichtigt wurden. Zugleich werden exemplarisch Hinweise auf Bezüge zum Wirtschaftsvölkerrecht gegeben. Das Buch ist trotz gewachsenem Umfang nach wie vor als Lehrbuch konzipiert. Wiederum wurden den einzelnen Paragrafen Ausgangsfragen vorangestellt, die mithilfe der Lektüre beantwortet werden können. "Übungsfälle" im Anschluss an einzelne Kapitel und "Lesepläne" animieren zur Vertiefung. Der Text und die Hinweise auf Judikatur und Gesetzgebung entsprechen dem Stand vom Mai 2006. Mehr lesen', 'amazon_de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-13 23:10:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Lxhlrzmq9PfO', 'Genetik in Cartoons', 'Larry Gonick; Mark Wheelis', 2001, 'Science, Education, Humor', 'science', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/1031061-L.jpg', 'A humorous and educational exploration of genetics, "Genetik in Cartoons" by Larry Gonick and Mark Wheelis uses engaging illustrations and witty commentary to simplif ...', 'pax-audit-openlibrary', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 13:21:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('GAXhU10xJi0-', 'Asterix – Gesamtausgabe, Band 15', 'René Goscinny; Albert Uderzo; Jean-Yves Ferri; Didier Conrad', 2024, 'Comics', 'comics', 'German', '978-3-7704-0349-3', 'Egmont Comic Collection', 224, 4.4, 55, NULL, '1.', 'Asterix – Gesamtausgabe', 15, NULL, NULL, 'https://m.media-amazon.com/images/I/81DpKXuBfsL.jpg', 'In dieser edlen, in Kunstleder gebundenen Gesamtausgabe kommen die Asterix-Abenteuer "Die Tochter des Vercingetorix", "Asterix und der Greif" und der brandneue Band "Die weiße Iris" zum Abdruck, sowie als besondere Zugabe der Sonderband "Der Goldene Hinkelstein". Komplettiert wird diese Ausgabe mit vielen Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experten Horst Berner. Mit diesem Band wird die Kunstleder-Gesamtausgabe beendet. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('dD8moanDvduC', 'Asterix – Gesamtausgabe, Band 14', 'René Goscinny; Albert Uderzo; Jean-Yves Ferri; Didier Conrad', 2019, 'Comics', 'comics', 'German', '978-3-7704-4025-2', 'Egmont Comic Collection', 192, 4.9, 42, NULL, '1.', 'Asterix – Gesamtausgabe', 14, NULL, NULL, 'https://m.media-amazon.com/images/I/815pjJR4pPL.jpg', 'Inzwischen liegen bereits drei Abenteuer aus der Feder der Uderzo-Nachfolger Ferri und Conrad vor. In dieser edlen, in Kunstleder gebundenen Gesamtausgabe kommen die Asterix-Abenteuer "Der Papyrus des Cäsar" und "Asterix in Italien" zum Abdruck. Sowie als besondere Zugabe das Filmalbum zum Kinofilm "Asterix erobert Rom". Dazu gibt es viele Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experten Horst Berner. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('qAeCHMkgVvlV', 'Asterix – Gesamtausgabe, Band 13', 'René Goscinny; Albert Uderzo; Jean-Yves Ferri; Didier Conrad', 2014, 'Comics', 'comics', 'German', '978-3-7704-3787-0', 'Egmont Comic Collection', 168, 4.8, 50, NULL, '1.', 'Asterix – Gesamtausgabe', 13, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/7704/3787/0/9783770437870xxl.webp', 'Ein Jahr nach Erscheinen des sensationellen Erfolgs-Albums "Asterix bei den Pikten" erscheint das Schotten-Abenteuer unserer gallischen Helden auch in der Asterix-Gesamtausgabe. In edles Kunstleder gebunden enthält dieser Band außerdem die Skizzen des neuen Asterix-Zeichners Didier Conrad sowie das 2009 erschienen Album "Asterix und Obelix feiern Geburtstag". Dazu gibt es viele Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experte Horst Berner. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('jmf10yuvIDs8', 'Asterix – Gesamtausgabe, Band 12', 'René Goscinny; Albert Uderzo', 2016, 'Comics', 'comics', 'German', '978-3-7704-3887-7', 'Egmont Comic Collection', 176, 4.6, 50, NULL, '1.', 'Asterix – Gesamtausgabe', 12, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/7704/3887/7/9783770438877xxl.webp', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Band 12 enthält mit "Asterix plaudert aus der Schule" eine Sammlung von Kurzgeschichten, die Uderzo und Goscinny ab 1966 zusätzlich zu den langen Abenteuern anfertigten. Hier erlaubten sie sich einige gestalterische und inhaltliche Freiheiten. Wer also Idefix in einer Sprechrolle sehen will oder wie die Autoren selbst einen Obelix-Doppelgänger treffen, bekommt hier die besondere Gelegenheit! Besonders ist auch der Besuch der Außerirdischen im gallischen Dorf in "Gallien in Gefahr". Die Skizzen zu diesem Album runden diesen Band der Gesamtausgabe ab. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('xkSMYYrKT3qK', 'Asterix – Gesamtausgabe, Band 11', 'René Goscinny; Albert Uderzo', 2017, 'Comics', 'comics', 'German', '978-3-7704-3900-3', 'Egmont Comic Collection', 176, 4.8, 44, NULL, '1.', 'Asterix – Gesamtausgabe', 11, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/7704/3900/3/9783770439003xxl.webp', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In "Asterix und Maestria" finden die Gallier ihr Meisterin, in "Obelix auf Kreuzfahrt" finden sie das sagenumwobene Atlantis und in "Asterix und Latraviata" erliegen sie weiblichen Reizen. Zusätzlich zu den Geschichte von Albert Uderzo enthält auch dieser Band der Asterix Gesamtausgabe einen unmfangreichen redaktionellen Teil. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('mUp8I_aYmrZc', 'Asterix – Gesamtausgabe, Band 10', 'René Goscinny; Albert Uderzo', 2014, 'Comics', 'comics', 'German', '978-3-7704-3726-9', 'Egmont Comic Collection', 168, 4.6, 23, NULL, '1.', 'Asterix – Gesamtausgabe', 10, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/7704/3726/9/9783770437269xxl.webp', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In "Asterix im Morgenland" schickt Albert Uderzo den kleinen Gallier in den Orient. Zusätzlich zur Geschichte kommen auch die von Uderzo angefertigten Skizzen zum Abdruck, die einen Einblick in die Entstehung eines Comicabenteuers geben. Zudem enthält der Band mit "Wie Obelix als kleines Kind in den Zaubertrank geplumpst ist" eine Erzählung, die René Goscinny schon 1965 schrieb und von Uderzo nach dessen Tod mit herrlichen großformatigen Bildern illustriert wurde. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('SwIsBM75fayl', 'Asterix – Gesamtausgabe, Band 9', 'René Goscinny; Albert Uderzo', 2013, 'Comics', 'comics', 'German', '978-3-7704-3711-5', 'Egmont Comic Collection', 168, 4.9, 48, NULL, '2.', 'Asterix – Gesamtausgabe', 9, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/7704/3711/5/9783770437115xxl.webp', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Nach dem Tode René Goscinnys übernahm Zeichner Albert Uderzo auch die Rolle des Szenaristen. In seinem ersten alleinigen Werk "Der große Graben" erzählt er "Romeo und Julia" auf Gallier-Art. Dann schickt er Asterix und Obelix auf "Die Odyssee" in den nahen Osten. In "Der Sohn des Asterix" verhilft er dem überzeugten Junggesellen schließlich zu unerwarteten Vaterfreunden, als ein Findelkind vor seiner Haustür liegt… Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('eSgKQhWjw32U', 'Asterix – Gesamtausgabe, Band 8', 'René Goscinny; Albert Uderzo', 2014, 'Comics', 'comics', 'German', '978-3-7704-3786-3', 'Egmont Comic Collection', 176, 4.8, 8, NULL, '1.', 'Asterix – Gesamtausgabe', 8, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/7704/3786/3/9783770437863xxl.webp', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Dieser Band enthält die Reise der Gallier nach Amerika in "Die große Überfahrt", Obelix als Geschäftsmann im Hinkelstein-Business in "Obelix GmbH & Co. KG" sowie "Asterix bei den Belgiern", das letzte Abenteuer, an dem der 1977 verstorbene Texter René Goscinny mitwirkte. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
