INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('O6WqE3XTpgJJ', 'Der Wüstenkrieg in Afrika', 'Janusz Piekalkiewicz', 2000, 'Military History', 'history', 'German', '9783828903579', 'Weltbild', 250, 4.3, 13, NULL, NULL, NULL, NULL, '["Afrika - Geschichte"]', NULL, 'https://books.google.com/books?vid=ISBN9783828903579&printsec=frontcover&img=1&zoom=3', 'A comprehensive account of the North African conflict during World War II, exploring key battles, strategies, and military leaders, with detailed analyses and historical photographs. Published in 1984, this work by Janusz Piekalkiewicz offers an in-depth exploration of the war efforts in the desert landscapes of Africa.', 'pax-audit-exlibris-ch', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:49:36');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('dJWYij-GbnTv', 'Seekrieg', 'Janusz Piekalkiewicz', 1980, 'Military History', 'history', 'German', '9783512008002', 'Almark Publishing Co.', 352, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8393409-L.jpg', 'A comprehensive exploration of naval warfare during World War II, detailing strategies, battles, and the impact of maritime conflicts with supporting illustrations and firsthand accounts.', 'original', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:06:52');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6Dr0HH2evyuI', 'Invasion', 'Janusz Piekalkiewicz', 1998, 'History', 'history', 'German', '9783828902794', 'Bechtermünz,', 320, 4.5, 9, NULL, 'Genehmigte Lizenzausgabe', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/91P5hHUhj3L.jpg', 'A historical account examining the strategies, tactics, and events of significant military invasions, detailing the complexities and consequences of these operations throughout history. Published in 1974 by Janusz Piekalkiewicz, this work offers insights into military history with an emphasis on factual reporting and analysis.', 'original', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:01:38');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('gQNMtwcO74vz', 'Luftkrieg', 'Janusz Piekalkiewicz', 1981, 'Military History', 'history', 'English', '978-0710601433', 'Bertelsmann', 269, 4.2, NULL, NULL, NULL, NULL, NULL, '["Merchant marine"]', NULL, 'https://covers.openlibrary.org/b/id/8414118-L.jpg', 'A comprehensive examination of aerial warfare during World War II, detailing strategies, significant battles, and technological advancements. The book combines historical analysis with firsthand accounts, providing a vivid portrayal of the impact of air power on the war''s outcome.', 'original', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:02:08');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('oKpgBrrX81Zm', 'Der Präzisions-Luftkrieg gegen Land und Leute', 'Raimund Müller', NULL, 'Non-fiction', 'non-fiction', 'German', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'A comprehensive analysis of the impact and strategies of precision air warfare on civilian populations and landscapes, exploring both historical and modern contexts.', 'needs-manual-upload', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 10:05:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('e7olJ1w1qCSW', 'Der Zweite Weltkrieg', 'R. Oldenbourg', 2022, 'History', 'history', 'German', '9783486588316', 'Walter de Gruyter', 450, NULL, NULL, NULL, NULL, NULL, NULL, '["History"]', NULL, 'https://exlibris.azureedge.net/covers/9783/4865/8831/6/9783486588316xxl.webp', 'Die Neufassung im bewährten Format beleuchtet die Griechische Geschichte vor dem Hellenismus (8. Jh. ‒ 320 v.Chr) in neuartiger Weise: als Teil eines weiträumigen und verflochtenen Geschehens im Mittelmeerraum und am Rand von Großreichen; dabei spielen Mobilität, Migration und Krieg eine zentrale Rolle. Einen weiteren Schwerpunkt bilden die Lust der Griechen an der Politik sowie ihre Kreativität auf diesem Feld. Dabei genießen regionale und lokale Eigenheiten besondere Aufmerksamkeit. Als Alleinstellungsmerkmal bietet der Band einen umfangreichen, mit der gegliederten Bibliographie eng verzahnten Forschungsüberblick. Dieser stellt die Geschichte der Hellenen als Problem vor und orientiert Studierende, aber auch Fachleute benachbarter Disziplinen gründlich und mit weitem Blick über die Kategorien, Konsense und Kontroversen.', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:49:43');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('xNLuudOROR2L', 'Der Erste Weltkrieg', 'Janusz Piekalkiewicz', 1988, 'History', 'history', 'German', '9783430174817', 'Econ Verlag', 608, 4.7, 37, NULL, NULL, NULL, NULL, '["World War, 1914-1918"]', NULL, 'https://m.media-amazon.com/images/I/71N5Koj6t-L.jpg', 'Comprehensive historical account of World War I, detailing major battles, strategies, and political influences, supported by photographs and firsthand accounts.', 'original', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:47:11');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('67IhUMr0ENuB', 'Flugzeugbewaffnung', 'Bill Gunston', 1988, 'Aviation History', 'history', 'German', NULL, NULL, 207, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8398909-L.jpg', 'An exploration of the development and technology of aircraft armament, detailing the evolution of weaponry and systems used in aviation, with insights into historical milestones and technical advancements by esteemed aviation author Bill Gunston.', 'pax-audit-openlibrary', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:56:27');
