INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-_RJbVN6pdtaI', 'Genetik in 30 Sekunden', 'Was ist die DNA und inwieweit bestimmen unsere Gene, wer wir sind? Wie wirkt eine Gentherapie? In den letzten hundert Jahren erlebte die Genetik atemberaubende Fortschritte. In diesem gut verständlichen Handbuch erfahren Sie alles Wesentliche zum Thema – von den Grundlagen bis aktuellen Forschungsergebnissen. Genetik in 30 Sekunden bricht den Fachjargon auf und berichtet von den Meilensteinen der Genetik, begonnen bei den Grundlagen der Zellbiologie bis zu den schier unglaublichen Entwicklungen in der DNA-Sequenzierung und der Genomchirurgie. Fortschritte bei der Stammzellentherapie, beim Klonen von Tieren, maßgeschneiderte Gentherapie und gentechnisch verändertes Getreide haben für Schlagzeilen gesorgt. Haben Sie sich je darüber Gedanken gemacht, was unter all dem zu verstehen ist und was das für unsere Zukunft bedeutet? Experten knacken in 50 Kapiteln den Code und entschlüsseln so die zentralen Begriffe und Ideen zur Genetik auf je einer Doppelseite in Wort und Bild. Dank der informativen Glossare, anschaulichen Grafiken und Biografien der wichtigsten Forscher werden Sie sich schon bald in diesem zentralen Wissenschaftsgebiet der Zukunft zu Hause fühlen. Mehr lesen', 'book', '["jonathan-weitzman", "matthew-weitzman"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-tC_qd23AduIY', 'Swiss Made', 'A comprehensive exploration of Switzerland''s economic success, "Swiss Made" by R. James Breiding delves into the factors contributing to the country''s global reputation for innovation, stability, and wealth. The book examines a range of industries, from finance and pharmaceuticals to technology and watchmaking, highlighting the cultural and historical influences that have shaped Switzerland''s unique business environment.', 'book', '["r-james-breiding"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-DJHRCgRo04-T', 'Der Crash kommt', 'An analysis of economic trends and warnings about an impending financial crisis, "Der Crash kommt" by Max Otte anticipates the economic challenges and disruptions that could lead to a significant market crash.', 'book', '["max-otte"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-cjiXHYQF4K1Q', 'Crashkurs – Dirk Müller', 'An engaging exploration of global financial markets, "Crashkurs" by Dirk Müller breaks down complex economic concepts for readers. Published in 2009, it offers insights into the causes and repercussions of the financial crisis, guiding readers through economic theories with practical advice and solutions. Known for his clear and approachable style, Müller provides a unique perspective from his experience in finance.', 'book', '["dirk-muller"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-raSRTUkjjLrZ', 'Six Sigma für Dummies', 'Improve your efficiency -- and bring in big profits! Need help implementing or understanding Six Sigma? Want to take this powerful problem-solving methodology and apply it to your business? Six Sigma isn''t just for Fortune 500 companies anymore; it''s for every business, even yours, no matter how big or small. This hands-on workbook provides the knowledge, insight, and practical exercises you need to master Six Sigma and put it to work in your business. Perfect as a companion workbook for Six Sigma For Dummies -- or any other Six Sigma book -- Six Sigma Workbook For Dummies gives you a wealth of examples, problems, and other tools you need to turn Six Sigma theory into practice -- today! Discover * How to form and lead a Six Sigma initiative * Project alignment with business objectives and strategy * How to create process flow maps and models * Chart and graph plotting for analysis and interpretation * Methods for calculating Sigma scores * How to quantify variable relationships Mehr lesen', 'book', '["craig-gygi", "bruce-williams", "neil-decarlo"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-E5uENuxFdwOr', 'Statistik mit Excel für Dummies', 'Java für Dummies ist gleichzeitig ein Lehrbuch und ein unverzichtbares Nachschlagewerk für alle Java-Programmierer. Basiswissen zur objektorientierten Programmierung wird genauso vermittelt wie das Prinzip der Wiederverwendbarkeit von Programmbausteinen und allgemeine Grundlagen der Java-Programmierung. Mehr lesen', 'book', '["joseph-schmuller"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-DOU7tony9Fgo', 'Übungsbuch Statistik für Dummies', 'A practical guide for students and professionals, providing clear explanations and exercises to master statistical concepts effectively.', 'book', '["deborah-j-rumsey"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ocTmmscYYc87', 'Statistik für Dummies', 'Wollen Sie wissen, was mit Ihrem Geld gemacht wird? Dann sind Aktien für Sie die richtige Wahl, denn Sie haben es als Mitunternehmer in der Hand, wem Sie Ihr Geld anvertrauen. Doch was ist eigentlich das Grundprinzip von Aktien? Welche Vorteile haben sie gegenüber anderen Anlageformen? Wie kommen Sie an Aktien und wie ordern Sie geschickt, um Chancen zu nutzenund Risiken überschaubar zu halten? Was beeinflusst Kurse und wie analysieren Sie Kursverläufe, um den richtigen Zeitpunkt für Kauf und Verkauf abzupassen? Wie können Sie mit ganz einfachen Mitteln, Ihre eigene Anlagestrategie entwickeln? Diese und viele weitere Fragen rund um Aktien, Kursverläufe und Börsenpsychologie beantworten Ihnen die beiden Aktienexperten Dr. Christine Bortenlänger und Ulrich Kirstein in diesem Buch, das für die Shortlist des deutschen Finanzbuchpreises nominiert wurde. Damit auch Sie schon bald von Kursen und Dividenden profitieren! Mehr lesen', 'book', '["deborah-j-rumsey"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-fh8gVaj1Wcxo', 'Logik für Dummies', 'Logik ist die Basis der Wissenschaft, aber auch eine Brücke zwischen Wissenschaft und Alltag, denn die Grundlagen sind einfach logisch. Doch so einfach sie auf den ersten Blick scheint, so anspruchsvoll ist sie im Detail. "Logik kompakt für Dummies" führt Sie systematisch und so einfach wie möglich in dieses Teilgebiet von Mathematik und Philosophie ein. Dabei arbeitet Mark Zegarelli mit anschaulichen Beispielen und schafft es so, dieses abstrakte Thema nicht nur verständlich zu erklären, sondern auch Wert und Nutzen der Logik aufzuzeigen. Mehr lesen', 'book', '["mark-zegarelli"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-vT4kARjSbiAc', 'XML für Dummies', 'Schlagzeug und Percussionsinstrumente gelten als leichter Einstieg in die Musik. Doch viele Anfänger stehen schon sehr bald vor dem Problem, die vielfältigen Möglichkeiten des Schlagzeugs zu meistern. Jeff Strong zeigt dem Leser, welche Instrumente zu einem Schlagzeug gehören und welche als Percussionsinstrumente eingesetzt werden. Vom einfachen Rhythmus bis zur lateinamerikanischen Musik, Jazz, Blues und Funk erfährt der Einsteiger alles Grundlegende zu Beats und Tempi. Mehr lesen', 'book', '["lucinda-dykes", "ed-tittel"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-klOfBdC281sw', 'Zeitmanagement für Dummies', '', 'book', '["dirk-mayer"]', '["self-help"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_6bc7a4389671', 'Wahrscheinlichkeitsrechnung für Dummies', 'Beim Thema Rechtschreibung zucken viele zusammen. Schon in der Schule waren den meisten Diktate ein Graus. Groß- oder kleinschreiben, auseinander oder zusammen, und wo überhaupt muss ein Komma stehen oder ein Bindestrich? Peinlich, wenn dann später das Bewerbungsschreiben vor Fehlern nur so strotzt, die Examensarbeit inhaltlich zwar top, in Sachen Orthografie aber ein Flop ist oder in der Geschäftskorrespondenz mit wichtigen Kunden unzählige Kommafehler stecken. Ebenfalls unschön, wenn Newsletter und Flyer mehr durch ihre mangelhafte Rechtschreibung als durch ihren Inhalt auffallen. Hinzu kommt die Gewissheit, dass auf das Korrekturprogramm des PC auch kein Verlass ist. Und obendrein noch das Hin und Her um die Rechtschreibung in den letzten Jahren. Wer weiß da überhaupt noch, was Sache ist? Sich auf der Suche nach dem Neuen durch das amtliche Regelwerk zu wühlen, ist ein mühsames Geschäft. Das muss auch gar nicht sein. Dr. Matthias Wermke, der Leiter der Dudenredaktion, verbindet in "Neue deutsche Rechtschreibung für Dummies" die Kompetenz des Dudens mit dem lockeren Stil der Dummies, der Berührungsängste vor trockenen Themen nimmt. Und auf einmal werden die Regeln der neuen deutschen Rechtschreibung sogar Orthografiemuffeln verständlich. Als besonderes Extra enthält der Band ein Wörterbuch mit 47.000 Stichwörtern. Mehr lesen', 'book', '["deborah-rumsey"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_24509925f484', 'Mathe in 30 Sekunden', '"Mathe in 30 Sekunden" by Richard J. Brown is a concise exploration of key mathematical concepts, designed to explain complex ideas in brief, easily digestible segments. Each topic is intended to take 30 seconds to understand, making it an accessible resource for anyone interested in the fundamentals of mathematics. The book covers a wide range of topics from geometry to calculus, providing an engaging summary of essential mathematical principles.', 'book', '["richard-j-brown"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_2971171ded6f', 'Newton in 30 Sekunden', 'Die Geschichte vom Apfel, der ihm auf den Kopf fiel, ist weltberühmt, aber was wissen Sie noch über Isaac Newton? Er war ein Multitalent – Physiker, Astronom, Alchemist und Mathematiker –, und die Genialität seines Werkes bahnte zahllosen wissenschaftlichen Entdeckungen den Weg. Frischen Sie Ihre Kenntnisse über sein beeindruckendes Erbe auf und lesen Sie Interessantes über ein Genie, das unsere Welt mitgeformt hat. Newton in 30 Sekunden vermittelt ein einzigartiges Bild eines der größten Genies aller Zeiten und präsentiert seine wichtigsten Ideen und Theorien. Jede Buchseite steckt voller Informationen: von seinen Entdeckungen zu Schwerkraft, Licht, Farben sowie Differential- und Integralrechnung bis zu seiner Zeit als Mitglied des Parlaments. Brian Clegg, Herausgeber, studierte Naturwissenschaften mit Schwerpunkt Experimentalphysik an der Universität Cambridge. Er schrieb für verschiedene Zeitschriften und Zeitungen wie Nature, The Times und The Wall Street Journal und unterrichtete an den Universitäten Oxford und Cambridge sowie der Royal Institution. Er ist Redakteur bei www.popularscience.co.uk und Verfasser zahlreicher Bücher, darunter Quantentheorie in 30 Sekunden. Mehr lesen', 'book', '["brian-clegg"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_b7c33e0b423d', 'Einstein in 30 Sekunden', 'Albert Einstein war ein bahnbrechendes Genie, dessen Ideen und Theorien die Wissenschaft revolutionierten. Mehr als einmal stellte er die Wahrnehmung des Universums auf den Kopf. Mit gerade einmal 26 Jahren sorgte der spätere Nobelpreisträger für wissenschaftlich spektakuläre Erkenntnisse. Albert Einstein war nicht nur ein herausragender Physiker, sondern außerdem ein Kämpfer für die Menschenrechte und ein politischer Aktivist. Einstein, der die wohl berühmteste Formel der modernen Physik E=mc2 formulierte, gilt bis heute als Prototyp des verschrobenen Professors. Einstein in 30 Sekunden eröffnet Ihnen die Gedankenwelt des wohl berühmtesten Physikers unserer Zeit, dessen außergewöhnliches Leben in gleichem Maße wie seine wissenschaftlichen Leistungen beeindruckt. Mit jedem der 50 informativen Kapitel werden sie Albert Einsteins Werk, Leben und Erbe besser verstehen – von der Relativitätstheorie über die Quantenphysik bis zur Kernspaltung. Mehr lesen', 'book', '["brian-clegg"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_ce9e5dcf9490', 'Mythologie in 30 Sekunden', 'Mythologie in 30 Sekunden beleuchtet die wichtigsten Inhalte der bekanntesten klassischen Mythen und erklärt deren verborgene Bedeutung. Das Buch behandelt den Ursprung von Göttern, Helden und Dämonen der alten Griechen und Römer und erläutert dem Leser die grundlegenden Aspekte ihrer Überlieferungen in einer halben Minute auf jeweils zwei Seiten, in rund dreihundert Wörtern und anhand einer Abbildung. Mythologie in 30 Sekunden enthält die Biografien der sieben größten Dichter und Dramatiker des Altertums und verdeutlicht kurz und prägnant den bleibenden Einfluss antiker Mythen. Mehr lesen', 'book', '["robert-a-segal"]', '["mythology"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_096439cc1d72', 'GRU – Die Speerspitze', 'Eigentlich hat sich Kommissar Laurenti auf eigenen ruhigen Triester Sommer eingestellt. Doch nach einem merkwürdigen Yacht-Unfall bekommt er es mit Mord, Geldwäsche und Menschenschmuggel zu tun. Darunter leidet nicht nur sein Familienleben ...', 'book', '["viktor-suworow"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_42ee89dbef0f', 'Kampf der Kulturen', 'An influential political science book that explores the theory of cultural conflicts shaping global politics post-Cold War, focusing on the idea that future wars would be fought not between countries, but between cultures.', 'book', '["samuel-p-huntington"]', '["political-science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_0cc2817c4d8f', 'Taktik gegen Terror', 'Rivers, Gayle: Taktik gegen den Terror. Zürich, Wiesbaden. Orell Füssli 1987. Gr-8vo. 213 S. OPb. mit OSchU. Umschlag berieben, druckspurig, leicht bestoßen und stockfleckig, Einband bestoßen, Schnitt (stock-)fleckig, Notiz auf Titel, Seitenkanten altersgemäß gebräunt, sonst in gutem Zustand. Mehr lesen', 'book', '["gayle-rivers"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_0db9e7c3007f', 'US Rangers', 'A comprehensive exploration of the history and operations of the US Rangers, detailing their evolution, key missions, and impact on military tactics, authored by David Schauer.', 'book', '["david-schauer"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_e4f4f2d38a43', 'Soldaten aus dem Dunkel', 'A chilling horror tale by Carl Jacobi, "Soldaten aus dem Dunkel" weaves a narrative of suspense and supernatural encounters, drawing readers into a world where darkness conceals malevolent forces.', 'book', '["carl-jacobi"]', '["horror"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_9f184abdafad', 'NSA – Amerikas geheimster Nachrichtendienst', 'An in-depth exploration of the National Security Agency (NSA), examining its secretive operations, history, and impact on global intelligence.', 'book', '["james-bamford"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_82cfc37b6a9c', 'Reagan und die geheimen Kriege der CIA', 'An investigative account by Bob Woodward detailing secret CIA operations during Ronald Reagan''s presidency, exploring the complexities and controversies of U.S. intelligence activities in the 1980s.', 'book', '["bob-woodward"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-bb0yOaScc7EE', 'Geheime Nachrichten-Technik', 'This volume is published in honor of Friedrich Hund''s 100th birthday. It is a modern review on matter at high densities and pressures in astrophysics from Hund''s early contribution to present-day ideas. The relation between the equation of state and the structure of compact cosmic objects is discussed, and two main contributions deal with the equation of state of baryonic matter at nuclear densities and with the numerical solution of the general relativistic field equations for non-rotating and rapidly rotating neutron stars. In a final chapter the present state of asteroseismology is presented as a tool to explore the interior of cosmic objects by analyzing the observed free oscillations of the Earth, the Sun, and white dwarf stars.', 'book', '["otto-schreier"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-fOcjD2CZC5jp', 'Nuclear Battlefields', 'A detailed examination of global nuclear weapons infrastructure during the Cold War, exploring the locations, strategies, and implications of nuclear arsenals and battlefields worldwide.', 'book', '["william-m-arkin", "richard-w-fieldhouse"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-IB83F_KcAMLt', 'Credit Risk Modeling using Excel and VBA', 'It is common to blame the inadequacy of credit risk models for the fact that the financial crisis has caught many market participants by surprise. On closer inspection, though, it often appears that market participants failed to understand or to use the models correctly. The recent events therefore do not invalidate traditional credit risk modeling as described in the first edition of the book. A second edition is timely, however, because the first dealt relatively briefly with instruments featuring prominently in the crisis (CDSs and CDOs). In addition to expanding the coverage of these instruments, the book will focus on modeling aspects which were of particular relevance in the financial crisis (e.g. estimation error) and demonstrate the usefulness of credit risk modelling through case studies. This book provides practitioners and students with an intuitive, hands-on introduction to modern credit risk modelling. Every chapter starts with an explanation of the methodology and then the authors take the reader step by step through the implementation of the methods in Excel and VBA. They focus specifically on risk management issues and cover default probability estimation (scoring, structural models, and transition matrices), correlation and portfolio analysis, validation, as well as credit default swaps and structured finance. The book has an accompanying website, https://creditriskmodeling.wordpress.com/, which has been specially updated for this Second Edition and contains slides and exercises for lecturers. Mehr lesen', 'book', '["gunter-loffler", "peter-n-posch"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xoKYLPLooJ1Y', 'Speed Reading', 'From the bestselling author of The Mind Map Book and Use Both Sides of Your Brain, dramatically increase your reading speed, comprehension, and retentionTony Buzan, world-famous expert in the field of the brain and the inventor of Mind Mapping, has gained international recognition with the methods outlined in Speed Reading. While it contains the traditional information on speed reading, this is the first book on the subject to utilize the latest discoveries about the astounding potential and intricate workings of your brain. In an easy-to-understand, direct style this classic guide provides: • New approaches to reading, study, concentration, and learning • Self-help tests designed to stimulate interest in different areas of knowledge • Measurement of your speed and comprehension to broaden your expertise. The revised Third Edition offers state-of-the-art techniques for improving reading speed and comprehension, from the simplest level to the most complex. Mehr lesen', 'book', '["tony-buzan"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-rNCGaoOV0CWb', 'MasterClass: Tony Buzan', 'A comprehensive guide by Tony Buzan on enhancing mental abilities and learning techniques, focusing on memory improvement, speed reading, and mind mapping strategies.', 'book', '["tony-buzan"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-YdjbaGjCMQGj', 'Exchange Traded Funds und Anlagestrategien: Das ETF-Praxisbuch', 'Exchange Traded Funds (ETFs) sind in den vergangenen Jahren zu einem wichtigen Baustein vieler Anlagedepots geworden. Dank breiter Risikodiversifikation, tiefen Kosten und einfacher Handelbarkeit werden sie nicht mehr nur von Privatanlegern eingesetzt. Auch professionelle Vermögensverwalter und institutionelle Anleger greifen vermehrt auf ETFs zurück. Aber wie funktionieren ETFs genau und welche Chancen und Risiken bieten sie? Welche Märkte decken sie ab? Auf was ist bei der ETF- bzw. Index-Wahl beim Investieren in Aktien, Anleihen, Rohstoffe, Hedge Funds usw. zu achten? Diese Themen sowie konkrete Einsatzmöglichkeiten von ETFs in Anlagestrategien und verschiedene Tipps bei der Umsetzung von Investitionsentscheidungen stehen im Mittelpunkt dieses Buches. Für das Verständnis von praktischen Herausforderungen bedarf es theoretischer Grundlagen. Auch diese kommen nicht zu kurz: Von der Theorie der Risikodiversifikation, den Optimierungsmethoden von Portfolios bis zu den Tücken des Tracking Errors. Die ausgewählten Themen sollen dem Leser eine kritische Auseinandersetzung mit häufig gestellten Fragen aus der Investmentwelt ermöglichen und Hilfestellung leisten. Nicht zu kurz kommen die Vorstellung der grössten ETF-Anbieter, Unterschiede zwischen den bekannten US-Aktienindizes wie S&P 500, Dow Jones und Nasdaq sowie viele weitere Fragestellungen aus der Praxis. Das Buch ist von Praktikern für Praktiker geschrieben und soll allen, die mehr rund um das Thema ETFs und Anlagestrategien wissen wollen, den Überblick erleichtern. Das vorliegende Buch eignet sich insbesondere für: Interessierte Privatanleger, Kundenberater, Portfoliomanager, Studenten und Journalisten. 28.06.2012 / NZZ: "Mit «Exchange Traded Funds und Anlagestrategien» geben Daniel Niedermayer und Marcel Wagner einen Leitfaden, um ETF zu verstehen und richtig einzusetzen." 20.06.2012 / FuW: "Ein neues, umfassendes Werk über Exchange Traded Funds liegt vor." Mehr lesen', 'book', '["norbert-niedermayer", "christian-wagner"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kxnAxRC41Buk', 'Managing Credit Risk (Second Edition)', 'Managing Credit Risk, Second Edition opens with a detailed discussion of today’s global credit markets―touching on everything from the emergence of hedge funds as major players to the growing influence of rating agencies. After gaining a firm understanding of these issues, you’ll be introduced to some of the most effective credit risk management tools, techniques, and vehicles currently available. If you need to keep up with the constant changes in the world of credit risk management, this book will show you how. Mehr lesen', 'book', '["john-caouette", "edward-i-altman", "paul-narayanan", "nimmo"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kx6XOx0dNO9A', 'Introduction to Swiss Law', 'A comprehensive guide to the legal framework of Switzerland, covering essential aspects of Swiss law for students, practitioners, and anyone interested in understanding the country''s legal system.', 'book', '["f-dessemontet", "t-ansay"]', '["legal"]', NULL, '2026-05-11 23:09:48');
