INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-VMht1W7sF133', 'Operational Risk', 'A comprehensive guide that explores the challenges and frameworks in managing operational risk in financial institutions, focusing on measurement techniques, regulatory considerations, and best practices in risk mitigation.', 'book', '["carol-alexander"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-9tZ0Ed7kAv7r', 'Market Risk Analysis, Vol. I: Quantitative Methods in Finance', 'Written by leading market risk academic, Professor Carol Alexander, Quantitative Methods in Finance forms part one of the Market Risk Analysis four volume set. Starting from the basics, this book helps readers to take the first step towards becoming a properly qualified financial risk manager and asset manager, roles that are currently in huge demand. Accessible to intelligent readers with a moderate understanding of mathematics at high school level or to anyone with a university degree in mathematics, physics or engineering, no prior knowledge of finance is necessary. Instead the emphasis is on understanding ideas rather than on mathematical rigour, meaning that this book offers a fast-track introduction to financial analysis for readers with some quantitative background, highlighting those areas of mathematics that are particularly relevant to solving problems in financial risk management and asset management. Unique to this book is a focus on both continuous and discrete time finance so that Quantitative Methods in Finance is not only about the application of mathematics to finance; it also explains, in very pedagogical terms, how the continuous time and discrete time finance disciplines meet, providing a comprehensive, highly accessible guide which will provide readers with the tools to start applying their knowledge immediately. All together, the Market Risk Analysis four volume set illustrates virtually every concept or formula with a practical, numerical example or a longer, empirical case study. Across all four volumes there are approximately 300 numerical and empirical examples, 400 graphs and figures and 30 case studies many of which are contained in interactive Excel spreadsheets available from the accompanying CD-ROM. Empirical examples and case studies specific to this volume include: Principal component analysis of European equity indices;Calibration of Student t distribution by maximum likelihood;Orthogonal regression and estimation of equity factor models;Simulations of geometric Brownian motion, and of correlated Student t variables;Pricing European and American options with binomial trees, and European options with the Black-Scholes-Merton formula;Cubic spline fitting of yields curves and implied volatilities;Solution of Markowitz problem with no short sales and other constraints;Calculation of risk adjusted performance metrics including generalised Sharpe ratio, omega and kappa indices. Mehr lesen', 'book', '["carol-alexander"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-icxsCAz7jkI2', 'Market Risk Analysis, Vol. II: Practical Financial Econometrics', 'Written by leading market risk academic, Professor Carol Alexander, Quantitative Methods in Finance forms part one of the Market Risk Analysis four volume set. Starting from the basics, this book helps readers to take the first step towards becoming a properly qualified financial risk manager and asset manager, roles that are currently in huge demand. Accessible to intelligent readers with a moderate understanding of mathematics at high school level or to anyone with a university degree in mathematics, physics or engineering, no prior knowledge of finance is necessary. Instead the emphasis is on understanding ideas rather than on mathematical rigour, meaning that this book offers a fast-track introduction to financial analysis for readers with some quantitative background, highlighting those areas of mathematics that are particularly relevant to solving problems in financial risk management and asset management. Unique to this book is a focus on both continuous and discrete time finance so that Quantitative Methods in Finance is not only about the application of mathematics to finance; it also explains, in very pedagogical terms, how the continuous time and discrete time finance disciplines meet, providing a comprehensive, highly accessible guide which will provide readers with the tools to start applying their knowledge immediately. All together, the Market Risk Analysis four volume set illustrates virtually every concept or formula with a practical, numerical example or a longer, empirical case study. Across all four volumes there are approximately 300 numerical and empirical examples, 400 graphs and figures and 30 case studies many of which are contained in interactive Excel spreadsheets available from the accompanying CD-ROM. Empirical examples and case studies specific to this volume include: Principal component analysis of European equity indices;Calibration of Student t distribution by maximum likelihood;Orthogonal regression and estimation of equity factor models;Simulations of geometric Brownian motion, and of correlated Student t variables;Pricing European and American options with binomial trees, and European options with the Black-Scholes-Merton formula;Cubic spline fitting of yields curves and implied volatilities;Solution of Markowitz problem with no short sales and other constraints;Calculation of risk adjusted performance metrics including generalised Sharpe ratio, omega and kappa indices. Mehr lesen', 'book', '["carol-alexander"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-0ILKr91IJxYr', 'Market Risk Analysis, Vol. IV: Value-at-Risk Models', 'Written by leading market risk academic, Professor Carol Alexander, Practical Financial Econometrics forms part two of the Market Risk Analysis four volume set. It introduces the econometric techniques that are commonly applied to finance with a critical and selective exposition, emphasising the areas of econometrics, such as GARCH, cointegration and copulas that are required for resolving problems in market risk analysis. The book covers material for a one-semester graduate course in applied financial econometrics in a very pedagogical fashion as each time a concept is introduced an empirical example is given, and whenever possible this is illustrated with an Excel spreadsheet. All together, the Market Risk Analysis four volume set illustrates virtually every concept or formula with a practical, numerical example or a longer, empirical case study. Across all four volumes there are approximately 300 numerical and empirical examples, 400 graphs and figures and 30 case studies many of which are contained in interactive Excel spreadsheets available from the the accompanying CD-ROM. Empirical examples and case studies specific to this volume include: Factor analysis with orthogonal regressions and using principal component factors;Estimation of symmetric and asymmetric, normal and Student t GARCH and E-GARCH parameters;Normal, Student t, Gumbel, Clayton, normal mixture copula densities, and simulations from these copulas with application to VaR and portfolio optimization;Principal component analysis of yield curves with applications to portfolio immunization and asset/liability management;Simulation of normal mixture and Markov switching GARCH returns;Cointegration based index tracking and pairs trading, with error correction and impulse response modelling;Markov switching regression models (Eviews code);GARCH term structure forecasting with volatility targeting;Non-linear quantile regressions with applications to hedging. Mehr lesen', 'book', '["carol-alexander"]', '["finance"]', NULL, '2026-05-11 23:09:48');
