INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-prCM2quNmjbC', 'Eselsbrücken (Duden)', 'Eselsbrücken sind kluge Sätze, die handfeste Informationen unvergesslich machen - und das seit Generationen! Wie erinnern wir uns an das "Gründungsjahr Roms" und an die "Reihenfolge der Planeten" oder dass man "nämlich ohne h schreibt" und dass "afrikanische Elefanten lange Ohren haben"? Diese Sammlung von mehr als 200 altbekannten und weniger bekannten Eselsbrücken samt eingängigen Erläuterungen bietet einen Fundus an Allgemeinbildung aus den Themengebieten Geschichte, Sprache, Geografie, Naturwissenschaften, Mathematik, Kunst und Alltagswissen. Mit ausführlichem Register zum schnellen Nachschlagen. Mehr lesen', 'book', '["wolfgang-riedel"]', '["reference"]', NULL, '2026-05-11 23:09:48');
