INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Rj3bmInoyjN2', 'Charttechnik – simplified', 'An der Technischen Analyse kommt heute kein seriöser Trader oder Investor mehr vorbei. Das wichtigste Instrument dabei: die Charttechnik. Ein Chart ist hierbei ein Diagramm, das den Kursverlauf des Wertpapiers über einen bestimmten Zeitraum darstellt. In diesem simplifi ed- Buch erklärt Ihnen John Murphy leicht verständlich und umfassend alle Grundlagen, um an den Finanzmärkten erfolgreich zu traden. Charts sind das Herz der Technischen Analyse. Er führt Sie umfassend in die Welt der Chartdiagramme ein, von Widerstandslinien bis V-Bottom, von Balkencharts bis Candlesticks. Das leicht verständlich und umfassend Einsteiger-Buch für alle, die ihre Anlageerfolge entscheidend verbessern wollen. Mehr lesen', 'book', '["john-j-murphy"]', '["finance"]', NULL, '2026-05-11 23:09:48');
