INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-nmKezVUlnOi_', 'Gewinnen mit Börsenzyklen', 'Gewinnen mit Börsenzyklen Jeder Anleger kennt Jahresanfangs-Rallyes, Jahresend-Rallyes und die Sommerkorrekturen der Börsen. Diese Börsenphasen entstehen aber nicht zufällig, sondern wiederholen sich permanent, folgen also einem zyklischen Muster. Gewinnen mit Börsenzyklen zeigt anhand der kompletten Kurshistorie von Dax (seit 1959) und Dow Jones (seit 1896) den typischen zyklischen Kursverlauf der Börsen. Dabei wird eine detaillierte Untersuchung aller Jahres-Zyklen, Wahl-Zyklen, Zyklen der 4-Jahres-Tiefs, unterjährigen Zyklen und Jahrzehnt-Zyklen vorgenommen, so dass Gesamtverlauf und damit Start und Ende der entsprechenden Zyklen klar und nachvollziehbar werden. In insgesamt 31 Zyklen-Portfolios werden darauf basierende Anlagemodelle vorgestellt, die fast ohne Aufwand und mit einem deutlich reduzierten Risiko eine massive Outperformance von Dax und Dow Jones ermöglichen. Gegenüber einer Buy-and-Hold-Strategie lassen die Gewinne unter zu Hilfenahme von Zyklen sogar um das bis zu 33-fache steigern! Daneben zeigt eine ausführliche Besprechung der Demographie-Zyklen und der Technologie-Zyklen, warum die nächsten Jahre außergewöhnliche Börsenperspektiven eröffnen. Als Zusammenfassung aller behandelten Zyklen ergeben sich folgende Prognosen: - Dax und Dow Jones haben die Tiefs des Jahrzehnts schon hinter sich! - Die laufende Hausse wird sich bis 2009/2010 fortsetzen! - Das Mindestkursziel sind 10.000 für den Dax und 26.000/29.000 für den Dow Jones! - Vielleicht entsteht aber sogar eine noch viel größere Börsenblase als 1999/2000. Das würde bis Ende des Jahrzehnts zu noch deutlich höheren Notierungen führen, worauf ab 2010 aber eine Extrem-Baisse folgen sollte! Das Buch erklärt alle dominierenden Zyklen und skizziert daraus das wahrscheinlichste Bild für den Börsenverlauf der nächsten Jahre. Gewinnen mit Börsenzyklen ist das ultimative Basiswerk zu einem bisher fast unbekannten Analyseansatz, der in den nächsten Jahren noch erheblich an Popularität gewinnen wird. Mehr lesen', 'book', '["thomas-muller"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Hb5oLXeEdba-', 'Die 24 Geheimnisse des George Soros', 'George Soros war bis zum Herbst 1992 nur wenigen außerhalb des Exklusivkreises der Hochfinanz ein Begriff. Das änderte sich schlagartig im September 1992: Er setzte darauf, daß Großbritannien aufgrund der immer flauer werdenden Wirtschaftslage zu einer Abwertung des britischen Pfundes gezwungen sein würde - und seine Spekulation ging auf. Als das Pfund am 15. September 1992 tatsächlich abgewertet wurde, verdiente Soros buchstäblich über Nacht eine Milliarde Dollar. - Ein Star war geboren. George Soros nimmt unbestritten den Rang des weltweit berühmtesten Investors ein. Kein anderer hat über einen so langen Zeitraum hinweg derart hervorragende Ergebnisse erzielt wie Soros. Einen besseren Lehrer als George Soros gibt es nicht. Seit 1969, dem Gründungsjahr seines Quantum-Fonds, hat Soros mit seinen Investitionen einen unglaublichen Rekord aufgestellt. Ein im Jahr 1969 in den Quantum-Fonds investierter Betrag von 1.000 Dollar wäre bei Wiederveranlagung der Dividenden bis zum Jah r 1995 auf 2,150.000 Dollar angewachsen. Dieses Buch gewährt einen Einblick in Soros'' Anlagestrategien. Viele dieser Denkansätze sind für den Kleinanleger ebenso anwendbar wie für den professionellen Investor. Zwar ist die Kenntnis der Geheimnisse hinter Soros'' Investitionserfolgen sicherlich keine Garantie dafür, daß der Leser über Nacht eine Milliarde Dollar verdienen wird. Doch kann er, indem er sich ein Bild von der Denk- und Arbeitsweise George Soros'' verschafft und seine Schlüsselstrategien gedanklich nachvollzieht, zu einem besseren Verständnis der komplexen Welt der Hochfinanz gelangen; er kann selbst ein gewisses Gespür dafür entwickeln, das Geschehen in den Finanzmärkten richtig zu interpretieren und daraus Gewinne zu erzielen. Mehr lesen', 'book', '["robert-slater"]', '["biography"]', NULL, '2026-05-11 23:09:48');
