INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-TyfsRx6-bL_9', 'Die Kunst des Krieges für Führungskräfte', 'A strategic business book that adapts the ancient wisdom of Sun Tzu''s "The Art of War" into practical advice for leaders and executives, providing insights into effective decision-making, management, and competitive strategies in the corporate world.', 'book', '["donald-g-krause"]', '["business"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-HQqA2_9lzZih', 'Es war einmal ein Zebra, das liebte die Algebra', 'Die köstlichen, spannenden Ministorys, zu heiter berührenden Versen verdichtet, sprühen vor Lebensfreude. Marty nutzt dabei die Tiefe und Bedeutungsvariationen der Worte und bietet dem Leser so die Möglichkeit, in eine weitere Ebene einzutauchen. Wie ansonsten bei seiner Arbeit mit Düften, geht der Parfumeur hier auf die »Seele« der Worte ein. Ein Geschenk im besten Sinne des Wortes. Mehr lesen', 'book', '["markus-marty"]', '["children-s-literature"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ZSU3ip4wncWj', 'Rhetorik – Handbuch der Redekunst (Band 2)', 'A comprehensive guide to the art of rhetoric, this volume by Roman Hofmeister delves into advanced techniques and strategies for effective public speaking, offering insights into persuasion, audience engagement, and speech crafting. Published in 2020, it serves as an essential resource for those looking to refine their communication skills in various contexts.', 'book', '["roman-hofmeister"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-1B-T-NtWTJbF', 'Rhetorik – Handbuch der Redekunst (Band 1)', 'Comprehensive guide to the art of rhetoric, offering insights into effective public speaking and persuasive communication techniques.', 'book', '["roman-hofmeister"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-rk9xerhM7ofC', 'Die 222 wichtigsten Fragen zu Derivaten', 'Ob Optionen, Futures oder Swaps – die Welt der Derivate ist vielfältig und für Privatanleger nicht immer leicht zu durchschauen. Oft können einem auch Banken und Anlageberater nicht weiterhelfen. Volker Meinel, selbst Banker mit einem offenen Ohr für seine Kunden, kämpft gegen diesen Missstand an. Nun hat Meinel seine jahrelangen Erfahrungen in 222 Fragen und Antworten zusammengefasst. Der Leser erhält einen optimalen Überblick über die Märkte und ist in der Lage, selbst erfolgreich an den weltweiten Finanzmärkten zu bestehen. - Der Autor bringt seine Erfahrung aus unzähligen Leserbriefen, Telefonaten und Messegesprächen ein - Ein weiteres Highlight aus der Reihe »Die 222 wichtigsten Fragen zu …« - Umfassende Einblicke in die Welt der Derivate - Durch das Frage-Antwort-Schema übersichtlich gegliedert Mehr lesen', 'book', '["volker-meinel"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6r6T20vq5oOS', 'Forex Conquered', 'Praise for FOREX CONQUERED "In this amazing book, John covers it all. From trading systemsto money management to emotions, he explains easily how to pullmoney consistently from the most complicated financial market inthe world. John packs more new, innovative information into thisbook than I have ever seen in a trading book before." —Rob Booker, independent currency trader "John Person is one of the few rare talents that are uniquelyqualified to help traders understand the process of successfultrading. With today''s markets becoming increasingly challenging,John has cut right into the essentials and brought forward themuch-needed tools of forex trading. This clear and well-organizedpublication is a major step forward in helping traders gain anedge. I would highly recommend Forex Conquered as a valuablehandbook for both aspiring and experienced traders alike." —Sandy Jadeja, Chief Market Analyst and EditorLondon StockExchange, London, England "Forex Conquered is a bold title, but this book deliversthe tools needed for successful forex trading. There is no fluffhere, just the wisdom of a trading veteran that I have alwaysrespected-and followed." —Michael Kahn, Editor, Quick Takes Pro market letterand Columnist, Barron''s Online "This is a wonderful, in-depth view into the explanation oftechnical analysis and prudent money management guidelines in theforex market." —Blake Morrow, President, 4XMadeEasy "Forex Conquered is a meaningful contribution to the growingnumber of books on forex trading. John Person provides aprofessional view of forex trading that readers will be able to useas a guide for strategies and tactics that work. The scope of thebook covers more than forex and includes salient aspects of futuresand option trading. It should be read and then re-read!" —Abe Cofnas, President, Learn4x.com Note: CD-ROM/DVD and other supplementary materials arenot included as part of eBook file.', 'book', '["john-l-person"]', '["finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-8uo8rUuYgdhc', 'Der Schwarze Schwan', 'Die Weltbestseller des großen Zufallsforschers Ein “Schwarzer Schwan” ist ein Ereignis, auf das drei Dinge zutreffen: Es ist erstens ein Ausreißer – es liegt außerhalb der regulären Erwartungen, nichts in der Vergangenheit weist darauf hin. Es hat zweitens enorme Auswirkungen. Drittens bringt uns die menschliche Natur dazu, im Nachhinein Erklärungen für sein Eintreten zu konstruieren, um es erklärbar und vorhersagbar zu machen. In diesem bahnbrechenden Buch, das mittlerweile weltweit zum Klassiker geworden ist, entwickelt Taleb seine einflussreiche Denkfigur und Maxime für die ungewisse Realität, in der wir leben und handeln. Talebs Weltbestseller – „Der Schwarze Schwan: Die Macht höchst unwahrscheinlicher Ereignisse“ und „Der Schwarze Schwan: Konsequenzen aus der Krise“ – in einem Band und eingeleitet mit einem neuen Essay des Autors »Eines der zwölf einflussreichsten Bücher seit dem Zweiten Weltkrieg.« (Sunday Times) »›Der Schwarze Schwan‹ hat meine Sicht auf die Welt verändert.« (Daniel Kahneman, Nobelpreisträger) Der Weltbestseller: übersetzt in 33 Sprachen mit über 3 Millionen verkauften Exemplaren »Taleb zerpflückt mit großer Lust und einem guten Schuss Polemik unseren offenbar unerschütterlichen Glauben an die Vorhersehbarkeit von Ereignissen.« (SWR)', 'book', '["nassim-nicholas-taleb"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-0XjBem6mtHxK', 'Zeitmanagement mit Outlook', 'A comprehensive guide on utilizing Microsoft Outlook for effective time management, written by Schwert, Wagner, and Obermayr. This non-fiction book provides strategies and tips for optimizing productivity and organizing tasks using Outlook''s features.', 'book', '["schwert", "wagner", "obermayr"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-MfS9FyVvUd9f', 'Fighter Wing', 'Now, for the first time, an insider''s look at an Air Force combat wing -- the planes, the technology, and the people . . . with Tom Clancy as your guide. Tom Clancy''s previous explorations of America''s armed forces, Submarine and Armored Cav, revealed exclusive, never-before-seen information an the people and technology that protect our nation. Now, the acclaimed author of Clear and Present Danger and Debt of Honor takes to the skies with the U. S. Air Force''s elite: the Fighter Wing. With his compelling style and unerring eye for detail, Clancy captures the thrill of takeoff, the drama of the dogfight, and the relentless dangers our fighter pilots face every day of their lives . . . showing readers what it really means to be the best of the best. Fighter Wing includes: Detailed analyses of the Air Force''s premier fighter planes, including the F-15 Eagle Exclusive photographs, illustrations, and diagrams An insider''s look at the people behind the planes and weapons Combat strategies and training techniques used by the U. S. Air Force', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-auoumYaNtDDw', 'Das Echo aller Furcht', 'Der Kalte Krieg scheint Vergangenheit, die Weltmächte verhandeln im Zeichen der Kooperation und setzen auf eine friedliche Zukunft. Doch hinter den Kulissen tickt eine gefährliche Zeitbombe, und ein seltsamer Bombenfund genügt, um einen weltumspannenden tödlichen Konflikt zu entfachen. Jack Ryan, Amerikas Geheimdienstmann für Top-Secret-Fälle, muss einen nahezu aussichtslosen Kampf gegen die Zeit gewinnen ...', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-fujtRVEV0NDu', 'Rainbow Six', 'An action-packed techno-thriller novel featuring an elite multinational counter-terrorism unit called Rainbow, led by John Clark, as they tackle various global threats with cutting-edge technology and intense tactical operations.', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-v22xVeqgfmdQ', 'Im Auge des Tigers', 'Die neue Form des internationalen Terrorismus fordert eine neue Generation von Jägern heraus: Es kommt die Zeit für Jack Ryan, Jr. und seinesgleichen. Ein Mann namens Mohammed sitzt in einem Wiener Kaffeehaus und schlägt einem Kolumbianer ein Geschäft vor: Mohammed hat ein starkes Netzwerk aus Agenten und Sympathisanten in ganz Europa und im Mittleren Osten, und der Kolumbianer ein ähnlich starkes Netzwerk im Drogenhandel Amerikas. Warum sollten sie nicht eine Allianz bilden? Das Potential für Profit wäre riesengroß – und das Potential für Zerstörung unvorstellbar.', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-LpzIOoT90DCE', 'Der Kardinal im Kreml', 'Von einem geheimen Ort in der Nähe der afghanischen Grenze aus haben Russen erstmals mit einem Laserstrahl einen US-Spionagesatelliten "geblendet". Ein Fall für Jack Ryan. «Ein Autor, der nicht in Science-fiction abdriftet, sondern realistische Ausgangssituationen spannend zum Roman verdichtet.» DER SPIEGEL', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-T9Z8XM8Gd0qC', 'Im Sturm', 'Das Attentat arabischer Fundamentalisten auf eines der wichtigsten Ölfelder Sibiriens bringt die GUS in einen fatalen Zugzwang. Um den Zusammenbruch ihrer maroden Wirtschaft zu verhindern, erzwingt Moskau sich Zugang zum Persischen Golf und schreckt auch vor einem Schlag gegen die NATO nicht zurück ...', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-5MjlkjYcDpo6', 'Der Schattenkrieg', 'Als kolumbianische Drogenbosse drei hochrangige US-Amerikaner töten, ist für den Geheimdienstmann Jack Ryan der Punkt erreicht, an dem er zurückschlagen muss. Er stellt eine Truppe kampferprobter Männer zusammen und führt sie in einen Schattenkrieg, in dem die üblichen Regeln nicht gelten.', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Vgbq-K_Y1G-N', 'Gnadenlos', 'John Kelly, ehemaliger US-Marine und Spezialist für riskante Missionen, erhält den Auftrag, amerikanische Geiseln aus Nordvietnam herauszuholen - eine beinahe aussichtslose Mission, zumal Kelly sich gerade durch einen privaten Rachefeldzug in Lebensgefahr gebracht hat. Ein Wettlauf gegen die Zeit beginnt, und der geringste Fehler könnte sein letzter sein ...', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Wst-0OfzmhAb', 'Befehl von oben', 'Jack Ryans schwerste Stunde Bei einem Flugzeugangriff auf das Kapitol kommt der amerikanische Präsident ums Leben. Spezialagent Jack Ryan, vor Kurzem zum Vizepräsidenten ernannt, muss von einem Tag auf den anderen die Amtsgeschäfte übernehmen. Derweil nutzen Amerikas Feinde ihre Chance: China und Taiwan stehen kurz vor einem Krieg, und der Iran plant, amerikanische Großstädte mit einem tödlichen Virus zu verseuchen ...', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-2__5JtUXjJ_D', 'Ehrenschuld', 'Jack Ryans härtester Einsatz Außenpolitisch stehen die USA kurz vor der Alarmstufe Rot. Man holt Jack Ryan als neuen Sicherheitsberater des Präsidenten an die vorderste Front. Doch bevor er loslegt, muss Ryan zuerst noch eine Ehrenschuld begleichen. Ein Politthriller der Sonderklasse! Mehr lesen', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-EbX3iNmGXb2U', 'Im Zeichen des Drachen', 'A gripping thriller set against the backdrop of international espionage and intrigue, "Im Zeichen des Drachen" weaves a complex tale of power struggles and clandestine operations. As tensions rise, protagonists must navigate a world filled with danger and deception, where allegiances are tested and nothing is what it seems.', 'book', '["marc-olden"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book--X1sZeJKiOPm', 'Gegen alle Feinde', 'Internationale Intrigen, explosive Action – der neue große Tom Clancy Seit Jahren tobt der Konflikt im Mittleren Osten. Nun sieht es so aus, dass sich der Kriegsschauplatz verlagert hat. Die Taliban bedienen sich für ihre Machenschaften eines mexikanischen Drogenkartells und tragen den Kampf ins Heimatland des Erzfeindes – in die Vereinigten Staaten von Amerika. Tom Clancy, der Meister des internationalen Politthrillers, stellt uns seinen neuen Helden vor: Ex-Navy-SEAL Max Moore. Und der steht allein – gegen alle Feinde.', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6nC6RXBto_LU', 'Ziel erfasst', 'A high-stakes thriller set in the world of espionage and military tactics, where intricate plots and international intrigue challenge characters to navigate a dangerous game of cat and mouse.', 'book', '["tom-clancy"]', '["thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-M366WVN8yNge', 'The European Dream', 'The European Dream by Jeremy Rifkin explores the evolving European identity and contrasts it with the American Dream. It delves into how Europe’s vision emphasizes community, sustainability, and quality of life over individual success and material wealth. Rifkin argues that the European model offers a more sustainable and equitable future for a globalized world.', 'book', '["jeremy-rifkin"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-R4trCgIlkTfv', 'The Age of Access', 'A compelling exploration of how the shift from ownership to access is transforming the economy, culture, and daily life, where traditional markets are being replaced by networks and services.', 'book', '["jeremy-rifkin"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-9KZtm5uDMO4Q', 'The Hydrogen Economy', 'Explores the potential of hydrogen as a sustainable energy source and its role in addressing global energy and environmental challenges.', 'book', '["jeremy-rifkin"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-KSL8EN6lEW-Q', 'The Biotech Century', 'Explores the profound impacts of biotechnology on society, economy, and the human experience, analyzing both the potential benefits and ethical concerns associated with genetic engineering and biological innovations.', 'book', '["jeremy-rifkin"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ai0JDC9kz4le', 'Das Quark und der Jaguar', 'A profound exploration of the complexities of nature, where the author, a Nobel Prize-winning physicist, delves into the interconnectedness of simple and complex phenomena, examining topics from particle physics to the processes of human consciousness and the universe''s intricate tapestry.', 'book', '["murray-gell-mann"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dl-tJXLrboMK', 'Einsteins Universum', 'A comprehensive exploration of Einstein''s theories, delving into the concepts of relativity and their impact on our understanding of the universe, presented in an accessible manner for a broad audience.', 'book', '["nigel-calder"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-UWsoKaP8FZ_c', 'Kitsch ist Geschmackssache', 'Explores the subjective nature of taste and kitsch, examining cultural, social, and personal factors that influence perceptions of aesthetic value.', 'book', '["anja-weber"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-eBeYLxrTwmfJ', 'Der Traum von der Einheit des Universums', 'A comprehensive exploration of the quest for a unified theory of fundamental forces, reflecting on the history, challenges, and scientific milestones in physics.', 'book', '["steven-weinberg"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-X3FOviQbQ2qy', 'Der grosse Entwurf', 'Warum existieren wir? – Neue Antworten auf die letzten fragen des Seins «Um das Universum auf fundamentalster Ebene zu verstehen, müssen wir nicht nur wissen, wie sich das Universum verhält, sondern auch, warum. Warum gibt es etwas und nicht einfach nichts? Warum existieren wir? Warum dieses besondere System von Gesetzen und nicht irgendein anderes? Das ist die letztgültige Frage nach dem Leben, dem Universum und dem ganzen Rest. Wir werden versuchen, sie in diesem Buch zu beantworten.» Stephen Hawking Mehr lesen', 'book', '["stephen-hawking", "leonard-mlodinow"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-pmrwOETwDPnn', 'Das Universum in der Nussschale', 'Über das surreale Wunder der modernen Raumzeit-Forschung Wie kam es, dass in einer bestimmten Phase der kosmischen Entwicklung Milliarden Sterne »angingen«, wie tickt das Uhrwerk, das sie dazu veranlaßte? Warum glüht der Himmel nicht, obwohl doch das ganze Universum glüht - oder stimmt das gar nicht? Warum bewegt sich das Universum von uns fort? Warum haben Raum und Zeit einen Anfang und sind nicht ewig? Warum ist die Welt nicht fest umrissen und endgültig? Warum sind wir eigentlich hier und nicht woanders? Gibt es im All andere Wesen, und wenn ja, wer sind sie, und wo sind sie? Die Suche nach der Formel, die das Universum erklärt, nach der »Theorie für alles« ist der heilige Gral der Physik. Stephen Hawking behandelt in ›Das Universum in der Nussschale‹ verschiedene Vorschläge dafür, wie zum Beispiel die String-Theorie und Super-Gravitation. Er zeigt, dass nicht jeder Raum, sondern auch jede Zeit eine Form annimmt. Er pokert mit Newton und Einstein, befasst sich mit der Frage, ob Zeitreisen möglich sind, sowie mit anderen kühnen Spekulationen und bietet einen einzigartigen Einblick in die Welt der modernen Astrophysik und Kosmologie. Taschenbuchausgabe auf der Grundlage der erweiterten Neuausgabe. Mit zahlreichen Abbildungen. Mehr lesen', 'book', '["stephen-hawking"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-HnzOuE694oGA', 'Wirtschaftsfreiheit und begrenzte Staatsverantwortung', 'Das Werk macht die Leserinnen und Leser mit den zentralen Elementen der schweizerischen Wirtschaftsverfassung vertraut und zeigt auf, wie der Gesetzgeber das Wirtschaftsverwaltungsrecht auf der Grundlage der Vorentscheide, Zielvorgaben und Aufträge des Verfassungsgebers ausgestaltet hat. Seit der dritten Auflage ist einerseits die neue Bundesverfassung in Kraft getreten, andererseits haben zahlreiche Bereiche des Wirtschaftsverwaltungsrechts umfassende Änderungen erfahren, die in der Neuauflage berücksichtigt wurden. Zugleich werden exemplarisch Hinweise auf Bezüge zum Wirtschaftsvölkerrecht gegeben. Das Buch ist trotz gewachsenem Umfang nach wie vor als Lehrbuch konzipiert. Wiederum wurden den einzelnen Paragrafen Ausgangsfragen vorangestellt, die mithilfe der Lektüre beantwortet werden können. "Übungsfälle" im Anschluss an einzelne Kapitel und "Lesepläne" animieren zur Vertiefung. Der Text und die Hinweise auf Judikatur und Gesetzgebung entsprechen dem Stand vom Mai 2006. Mehr lesen', 'book', '["klaus-a-vallender", "jens-lehne", "peter-hettich"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Lxhlrzmq9PfO', 'Genetik in Cartoons', 'A humorous and educational exploration of genetics, "Genetik in Cartoons" by Larry Gonick and Mark Wheelis uses engaging illustrations and witty commentary to simplif ...', 'book', '["larry-gonick", "mark-wheelis"]', '["science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-GAXhU10xJi0-', 'Asterix – Gesamtausgabe, Band 15', 'In dieser edlen, in Kunstleder gebundenen Gesamtausgabe kommen die Asterix-Abenteuer "Die Tochter des Vercingetorix", "Asterix und der Greif" und der brandneue Band "Die weiße Iris" zum Abdruck, sowie als besondere Zugabe der Sonderband "Der Goldene Hinkelstein". Komplettiert wird diese Ausgabe mit vielen Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experten Horst Berner. Mit diesem Band wird die Kunstleder-Gesamtausgabe beendet. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dD8moanDvduC', 'Asterix – Gesamtausgabe, Band 14', 'Inzwischen liegen bereits drei Abenteuer aus der Feder der Uderzo-Nachfolger Ferri und Conrad vor. In dieser edlen, in Kunstleder gebundenen Gesamtausgabe kommen die Asterix-Abenteuer "Der Papyrus des Cäsar" und "Asterix in Italien" zum Abdruck. Sowie als besondere Zugabe das Filmalbum zum Kinofilm "Asterix erobert Rom". Dazu gibt es viele Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experten Horst Berner. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-qAeCHMkgVvlV', 'Asterix – Gesamtausgabe, Band 13', 'Ein Jahr nach Erscheinen des sensationellen Erfolgs-Albums "Asterix bei den Pikten" erscheint das Schotten-Abenteuer unserer gallischen Helden auch in der Asterix-Gesamtausgabe. In edles Kunstleder gebunden enthält dieser Band außerdem die Skizzen des neuen Asterix-Zeichners Didier Conrad sowie das 2009 erschienen Album "Asterix und Obelix feiern Geburtstag". Dazu gibt es viele Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experte Horst Berner. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-jmf10yuvIDs8', 'Asterix – Gesamtausgabe, Band 12', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Band 12 enthält mit "Asterix plaudert aus der Schule" eine Sammlung von Kurzgeschichten, die Uderzo und Goscinny ab 1966 zusätzlich zu den langen Abenteuern anfertigten. Hier erlaubten sie sich einige gestalterische und inhaltliche Freiheiten. Wer also Idefix in einer Sprechrolle sehen will oder wie die Autoren selbst einen Obelix-Doppelgänger treffen, bekommt hier die besondere Gelegenheit! Besonders ist auch der Besuch der Außerirdischen im gallischen Dorf in "Gallien in Gefahr". Die Skizzen zu diesem Album runden diesen Band der Gesamtausgabe ab. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xkSMYYrKT3qK', 'Asterix – Gesamtausgabe, Band 11', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In "Asterix und Maestria" finden die Gallier ihr Meisterin, in "Obelix auf Kreuzfahrt" finden sie das sagenumwobene Atlantis und in "Asterix und Latraviata" erliegen sie weiblichen Reizen. Zusätzlich zu den Geschichte von Albert Uderzo enthält auch dieser Band der Asterix Gesamtausgabe einen unmfangreichen redaktionellen Teil. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-mUp8I_aYmrZc', 'Asterix – Gesamtausgabe, Band 10', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In "Asterix im Morgenland" schickt Albert Uderzo den kleinen Gallier in den Orient. Zusätzlich zur Geschichte kommen auch die von Uderzo angefertigten Skizzen zum Abdruck, die einen Einblick in die Entstehung eines Comicabenteuers geben. Zudem enthält der Band mit "Wie Obelix als kleines Kind in den Zaubertrank geplumpst ist" eine Erzählung, die René Goscinny schon 1965 schrieb und von Uderzo nach dessen Tod mit herrlichen großformatigen Bildern illustriert wurde. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-SwIsBM75fayl', 'Asterix – Gesamtausgabe, Band 9', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Nach dem Tode René Goscinnys übernahm Zeichner Albert Uderzo auch die Rolle des Szenaristen. In seinem ersten alleinigen Werk "Der große Graben" erzählt er "Romeo und Julia" auf Gallier-Art. Dann schickt er Asterix und Obelix auf "Die Odyssee" in den nahen Osten. In "Der Sohn des Asterix" verhilft er dem überzeugten Junggesellen schließlich zu unerwarteten Vaterfreunden, als ein Findelkind vor seiner Haustür liegt… Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-eSgKQhWjw32U', 'Asterix – Gesamtausgabe, Band 8', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Dieser Band enthält die Reise der Gallier nach Amerika in "Die große Überfahrt", Obelix als Geschäftsmann im Hinkelstein-Business in "Obelix GmbH & Co. KG" sowie "Asterix bei den Belgiern", das letzte Abenteuer, an dem der 1977 verstorbene Texter René Goscinny mitwirkte. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-JTUjGHtjP1wt', 'Asterix – Gesamtausgabe, Band 7', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In Band 7 sorgt "Der Seher" im Dorf für Unruhe, denn die abergläubischen Bewohner glauben seine Vorhersagen – nur Asterix behält den Durchblick. In "Asterix auf Korsika" begeben sich unsere Freunde auf eine Reise auf die Mittelmeerinsel, deren Bewohner selbst für Asterix-Verhältnisse reichlich skurril sind. Und "Das Geschenk Cäsars" sorgt dafür, dass Majestix zum Wahlkampf um das Häuptlingsamt herausgefordert wird… Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-btPNMnQoOSAd', 'Asterix – Gesamtausgabe, Band 6', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In diesem Band: Bei den Schweizern treffen Asterix und Obelix auf Kuckucksuhren, Banken und die heilende Kraft des Edelweiß. In "Die Trabantenstadt" will Cäsar die Zukunft in die Antike bringen, indem er eine moderne Römersiedlung rings um das gallische Dorf bauen lässt. Und schließlich geht Häuptling Majestix eine Wette ein, er könne "Die Lorbeeren des Cäsar" beschaffen. Ausbaden dürfen diese vollmundige Ankündigung natürlich Asterix und Obelix… Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6AnG_8qIYOlH', 'Asterix – Gesamtausgabe, Band 5', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Dieser Band enthält die Alben "Asterix und der Kupferkessel", in dem der Gallier seine ganz persönliche Finanzkrise lösen muss, sowie "Asterix in Spanien", in dem er sich ins Land von Flamenco und Toreros aufmacht. Und im dritten Abenteuer versucht ein Zwietracht säender Römer im gallischen Dorf einen "Streit um Asterix" vom Zaun zu brechen. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kkk1HBojmskY', 'Asterix – Gesamtausgabe, Band 4', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In diesem Band mischen Asterix und Obelix die römische Armee auf, planen einen Triumphzug und starten bei Olympia als Favoriten – dank Zaubertrank-Doping! Mit "Asterix als Legionär", "Asterix und der Arvenerschild" und "Asterix bei den Olympischen Spielen" enthält dieser Band drei der beliebtesten Abenteuer der Reihe. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-TuoSvF9I02nC', 'Asterix – Gesamtausgabe, Band 3', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Band 3 enthält drei legendäre Abenteuer: Majestix muss sich dem "Kampf der Häuptlinge" stellen, Asterix macht sich auf zu den Briten, die, nur weil die Römer einfallen, noch lange nicht ihre Teestunde absagen, und schließlich greifen die furchtlosen Normannen das gallische Dorf an. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-2hh--Og3q9fv', 'Asterix – Gesamtausgabe, Band 2', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In den klassischen Abenteuern dieses Bandes gehen Asterix und Obelix auf Reisen: erst kämpfen sie als Gladiatoren in Rom für die Freiheit des entführten Troubadix, dann absolvieren sie eine antike Tour de France durch ganz Gallien und im fernen Ägypten treffen sie auf Königin Kleopatra. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-5OHLK-KDZ9Ki', 'Asterix – Gesamtausgabe, Band 1', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Der erste Band der Reihe enthält "Asterix der Gallier", in dem unser Held 1959 sein Debüt gab, sowie die Abenteuer "Die goldene Sichel" und "Asterix und die Goten". Mit diesen Frühwerken legten Goscinny und Uderzo die Grundsteine für eine der erfolgreichsten Comicserien aller Zeiten! Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-O6WqE3XTpgJJ', 'Der Wüstenkrieg in Afrika', 'A comprehensive account of the North African conflict during World War II, exploring key battles, strategies, and military leaders, with detailed analyses and historical photographs. Published in 1984, this work by Janusz Piekalkiewicz offers an in-depth exploration of the war efforts in the desert landscapes of Africa.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dJWYij-GbnTv', 'Seekrieg', 'A comprehensive exploration of naval warfare during World War II, detailing strategies, battles, and the impact of maritime conflicts with supporting illustrations and firsthand accounts.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6Dr0HH2evyuI', 'Invasion', 'A historical account examining the strategies, tactics, and events of significant military invasions, detailing the complexities and consequences of these operations throughout history. Published in 1974 by Janusz Piekalkiewicz, this work offers insights into military history with an emphasis on factual reporting and analysis.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-gQNMtwcO74vz', 'Luftkrieg', 'A comprehensive examination of aerial warfare during World War II, detailing strategies, significant battles, and technological advancements. The book combines historical analysis with firsthand accounts, providing a vivid portrayal of the impact of air power on the war''s outcome.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-oKpgBrrX81Zm', 'Der Präzisions-Luftkrieg gegen Land und Leute', 'A comprehensive analysis of the impact and strategies of precision air warfare on civilian populations and landscapes, exploring both historical and modern contexts.', 'book', '["raimund-muller"]', '["non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-e7olJ1w1qCSW', 'Der Zweite Weltkrieg', 'Die Neufassung im bewährten Format beleuchtet die Griechische Geschichte vor dem Hellenismus (8. Jh. ‒ 320 v.Chr) in neuartiger Weise: als Teil eines weiträumigen und verflochtenen Geschehens im Mittelmeerraum und am Rand von Großreichen; dabei spielen Mobilität, Migration und Krieg eine zentrale Rolle. Einen weiteren Schwerpunkt bilden die Lust der Griechen an der Politik sowie ihre Kreativität auf diesem Feld. Dabei genießen regionale und lokale Eigenheiten besondere Aufmerksamkeit. Als Alleinstellungsmerkmal bietet der Band einen umfangreichen, mit der gegliederten Bibliographie eng verzahnten Forschungsüberblick. Dieser stellt die Geschichte der Hellenen als Problem vor und orientiert Studierende, aber auch Fachleute benachbarter Disziplinen gründlich und mit weitem Blick über die Kategorien, Konsense und Kontroversen.', 'book', '["r-oldenbourg"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xNLuudOROR2L', 'Der Erste Weltkrieg', 'Comprehensive historical account of World War I, detailing major battles, strategies, and political influences, supported by photographs and firsthand accounts.', 'book', '["janusz-piekalkiewicz"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-67IhUMr0ENuB', 'Flugzeugbewaffnung', 'An exploration of the development and technology of aircraft armament, detailing the evolution of weaponry and systems used in aviation, with insights into historical milestones and technical advancements by esteemed aviation author Bill Gunston.', 'book', '["bill-gunston"]', '["history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Q2ai5IUOExuJ', 'Es war einmal ein Zebra, das liebte die Algebra', 'A whimsical children''s story about a zebra with a passion for algebra, exploring imaginative adventures and mathematical concepts through playful narratives.', 'book', '["markus-marty"]', '["children-s-literature"]', NULL, '2026-05-11 23:09:48');
COMMIT;
